"use client"

// Inspired by react-hot-toast library
import React from "react"
import type {
  ToastActionElement,
  ToastProps,
} from "@/components/ui/toast"

const TOAST_LIMIT = 1
const TOAST_REMOVE_DELAY = 1000000

type ToasterToast = ToastProps & {
  id: string
  title?: React.ReactNode
  description?: React.ReactNode
  action?: ToastActionElement
}

const actionTypes = {
  ADD_TOAST: "ADD_TOAST",
  UPDATE_TOAST: "UPDATE_TOAST",
  DISMISS_TOAST: "DISMISS_TOAST",
  REMOVE_TOAST: "REMOVE_TOAST",
} as const

let count = 0

function genId() {
  count = (count + 1) % Number.MAX_SAFE_INTEGER
  return count.toString()
}

type ActionType = typeof actionTypes

type Action =
  | {
    type: ActionType["ADD_TOAST"]
    toast: ToasterToast
  }
  | {
    type: ActionType["UPDATE_TOAST"]
    toast: Partial<ToasterToast>
  }
  | {
    type: ActionType["DISMISS_TOAST"]
    toastId?: ToasterToast["id"]
  }
  | {
    type: ActionType["REMOVE_TOAST"]
    toastId?: ToasterToast["id"]
  }

interface State {
  toasts: ToasterToast[]
}

const toastTimeouts = new Map<string, ReturnType<typeof setTimeout>>()

const addToRemoveQueue = (toastId: string) => {
  if (toastTimeouts.has(toastId)) {
    return
  }

  const timeout = setTimeout(() => {
    toastTimeouts.delete(toastId)
    dispatch({
      type: "REMOVE_TOAST",
      toastId: toastId,
    })
  }, TOAST_REMOVE_DELAY)

  toastTimeouts.set(toastId, timeout)
}

export const reducer = (state: State, action: Action): State => {
  switch (action.type) {
    case "ADD_TOAST":
      return {
        ...state,
        toasts: [action.toast, ...state.toasts].slice(0, TOAST_LIMIT),
      }

    case "UPDATE_TOAST":
      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === action.toast.id ? { ...t, ...action.toast } : t
        ),
      }

    case "DISMISS_TOAST": {
      const { toastId } = action

      // ! Side effects ! - This could be extracted into a dismissToast() action,
      // but I'll keep it here for simplicity
      if (toastId) {
        addToRemoveQueue(toastId)
      } else {
        state.toasts.forEach((toast) => {
          addToRemoveQueue(toast.id)
        })
      }

      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === toastId || toastId === undefined
            ? {
              ...t,
              open: false,
            }
            : t
        ),
      }
    }
    case "REMOVE_TOAST":
      if (action.toastId === undefined) {
        return {
          ...state,
          toasts: [],
        }
      }
      return {
        ...state,
        toasts: state.toasts.filter((t) => t.id !== action.toastId),
      }
  }
}

const listeners: Array<(state: State) => void> = []

let memoryState: State = { toasts: [] }

function dispatch(action: Action) {
  memoryState = reducer(memoryState, action)
  listeners.forEach((listener) => {
    listener(memoryState)
  })
}

type Toast = Omit<ToasterToast, "id">

function toast({ ...props }: Toast) {
  const id = genId()

  const update = (props: ToasterToast) =>
    dispatch({
      type: "UPDATE_TOAST",
      toast: { ...props, id },
    })
  const dismiss = () => dispatch({ type: "DISMISS_TOAST", toastId: id })

  dispatch({
    type: "ADD_TOAST",
    toast: {
      ...props,
      id,
      open: true,
      onOpenChange: (open) => {
        if (!open) dismiss()
      },
    },
  })

  return {
    id: id,
    dismiss,
    update,
  }
}

function useToast() {
  const [state, setState] = React.useState<State>(memoryState)

  React.useEffect(() => {
    listeners.push(setState)
    return () => {
      const index = listeners.indexOf(setState)
      if (index > -1) {
        listeners.splice(index, 1)
      }
    }
  }, [state])

  return {
    ...state,
    toast,
    dismiss: (toastId?: string) => dispatch({ type: "DISMISS_TOAST", toastId }),
  }
}

export { useToast, toast }

import React, { useEffect, useState } from 'react';
import { createCardapio } from '../../services/api/cardapios';
import { getFichas, type Ficha } from '../../services/api/fichas';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { useNavigate } from 'react-router-dom';

const TIPOS_ESCOLA_OPCOES = ["Creche", "Integral", "Parcial"];

export const CardapioForm: React.FC = () => {
  const [fichas, setFichas] = useState<Ficha[]>([]);
  const [fichaId, setFichaId] = useState('');
  const [date, setDate] = useState('');

  // Novos estados
  const [isFeriado, setIsFeriado] = useState(false);
  const [tiposEscola, setTiposEscola] = useState<string[]>([]);

  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    const fetchFichas = async () => {
      try {
        const data = await getFichas();
        setFichas(data);
      } catch (error) {
        console.error('Erro ao carregar fichas:', error);
      }
    };
    fetchFichas();
  }, []);

  const handleTipoEscolaChange = (tipo: string) => {
    setTiposEscola((prev) => 
      prev.includes(tipo) 
        ? prev.filter((t) => t !== tipo) 
        : [...prev, tipo]
    );
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!date) {
      setError('A Data de Agendamento ├® obrigat├│ria.');
      return;
    }

    if (!isFeriado && !fichaId) {
      setError('A Ficha T├®cnica ├® obrigat├│ria em dias normais (n├úo feriado).');
      return;
    }

    if (tiposEscola.length === 0) {
      setError('Selecione pelo menos um Tipo de Escola.');
      return;
    }

    setLoading(true);
    setError('');

    let formattedDate = date;
    if (date.includes('T')) {
      formattedDate = new Date(date).toISOString().split('T')[0];
    } else {
      formattedDate = new Date(`${date}T00:00:00`).toISOString().split('T')[0];
    }

    try {
      await createCardapio({
        date: formattedDate,
        fichaId: isFeriado ? undefined : fichaId,
        is_feriado: isFeriado,
        tipos_escola: tiposEscola
      });
      navigate('/cardapios');
    } catch (err: any) {
      console.error(err);
      setError('Erro ao criar o card├ípio. Verifique os dados e tente novamente.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="p-8 max-w-xl mx-auto flex flex-col gap-6">
      <div className="flex items-center justify-between">
        <h1 className="text-3xl font-bold text-slate-800">Agendar Novo Card├ípio</h1>
        <Button variant="outline" onClick={() => navigate('/cardapios')}>Voltar</Button>
      </div>

      <form onSubmit={handleSave} className="flex flex-col gap-6 bg-white p-6 rounded-md shadow-sm border border-slate-200">

        {/* Data */}
        <div className="flex flex-col gap-2">
          <Label htmlFor="date">Data de Agendamento <span className="text-red-500">*</span></Label>
          <Input 
            id="date" 
            type="date"
            value={date} 
            onChange={(e) => setDate(e.target.value)} 
          />
        </div>

        {/* Feriado (Switch) */}
        <div className="flex items-center justify-between p-3 border border-slate-100 bg-slate-50 rounded-md">
          <div className="flex flex-col gap-1">
            <Label htmlFor="isFeriado" className="font-semibold text-slate-800 cursor-pointer">├ë Feriado/Facultativo?</Label>
            <span className="text-xs text-slate-500">O card├ípio ser├í desativado neste dia para as escolas.</span>
          </div>
          <label className="relative inline-flex items-center cursor-pointer">
            <input 
              type="checkbox" 
              className="sr-only peer" 
              checked={isFeriado}
              onChange={(e) => {
                setIsFeriado(e.target.checked);
                if (e.target.checked) setFichaId(''); // Limpa a ficha se for feriado
              }}
            />
            <div className="w-11 h-6 bg-slate-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-slate-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-blue-600"></div>
          </label>
        </div>

        {/* Ficha T├®cnica (Oculto se for Feriado) */}
        {!isFeriado && (
          <div className="flex flex-col gap-2 animate-in fade-in slide-in-from-top-2 duration-300">
            <Label htmlFor="ficha">Ficha T├®cnica <span className="text-red-500">*</span></Label>
            <Select value={fichaId} onValueChange={setFichaId}>
              <SelectTrigger id="ficha">
                <SelectValue placeholder="Selecione a Ficha T├®cnica" className="text-slate-900" />
              </SelectTrigger>
              <SelectContent>
                {fichas.map((ficha) => (
                  <SelectItem key={ficha.id} value={String(ficha.id)} className="text-slate-900">
                    {ficha.name}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
        )}

        {/* Filtro de Escolas (Multi-select / Checkboxes) */}
        <div className="flex flex-col gap-3">
          <Label>Tipos de Escola <span className="text-red-500">*</span></Label>
          <div className="grid grid-cols-2 gap-3 p-3 border border-slate-100 rounded-md">
            {TIPOS_ESCOLA_OPCOES.map((tipo) => (
              <label key={tipo} className="flex items-center gap-2 cursor-pointer group">
                <div className="relative flex items-center justify-center">
                  <input
                    type="checkbox"
                    className="w-4 h-4 text-blue-600 bg-white border-slate-300 rounded focus:ring-blue-500 cursor-pointer"
                    checked={tiposEscola.includes(tipo)}
                    onChange={() => handleTipoEscolaChange(tipo)}
                  />
                </div>
                <span className="text-sm text-slate-700 group-hover:text-slate-900 transition-colors">{tipo}</span>
              </label>
            ))}
          </div>
        </div>

        {error && (
          <div className="bg-red-50 border-l-4 border-red-500 p-3 rounded-r-md">
            <p className="text-sm font-medium text-red-800">{error}</p>
          </div>
        )}

        <Button type="submit" className="mt-2 py-6 text-md font-semibold" disabled={loading}>
          {loading ? 'Processando Registro...' : (isFeriado ? 'Salvar Feriado Global' : 'Agendar Card├ípio Di├írio')}
        </Button>
      </form>
    </div>
  );
};

import React, { useEffect, useState, useMemo } from 'react';
import { createCardapio, getCardapios, updateCardapio, deleteCardapio, type Cardapio } from '../../services/api/cardapios';
import { getFichas, type Ficha } from '../../services/api/fichas';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter, DialogDescription } from '@/components/ui/dialog';
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from '@/components/ui/alert-dialog';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Pencil, Trash2, Plus, ChevronLeft, ChevronRight, CalendarDays, AlertTriangle, Copy } from 'lucide-react';
import { useToast } from '@/hooks/use-toast';
const TIPOS_ESCOLA_OPTIONS = ['CRECHE', 'FUNDAMENTAL', 'INTEGRAL', 'PARCIAL', 'EJA'];
const DIAS_SEMANA = ['Segunda', 'Ter├ºa', 'Quarta', 'Quinta', 'Sexta'];
const MESES = ['Janeiro', 'Fevereiro', 'Mar├ºo', 'Abril', 'Maio', 'Junho', 'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'];

const getLocalToday = (): string => {
  const now = new Date();
  return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;
};

const toDateString = (iso: string): string => iso.substring(0, 10);

/**
 * Gera as semanas ├║teis (Seg-Sex) de um m├¬s.
 * Cada semana ├® um array de 5 slots (null = dia fora do m├¬s ou fim de semana preenchido).
 * Cada slot: { day: number, dateStr: 'YYYY-MM-DD' }
 */
const getWeeksOfMonth = (year: number, month: number) => {
  const weeks: ({ day: number; dateStr: string } | null)[][] = [];
  const daysInMonth = new Date(year, month, 0).getDate(); // month is 1-based here

  let currentWeek: ({ day: number; dateStr: string } | null)[] = [];

  for (let day = 1; day <= daysInMonth; day++) {
    // JS Date month is 0-based
    const date = new Date(year, month - 1, day);
    const dow = date.getDay(); // 0=Sun, 1=Mon ... 6=Sat

    if (dow === 0 || dow === 6) continue; // Pula s├íbado e domingo

    // dow: 1=Mon -> index 0, 2=Tue -> index 1, etc.
    const weekdayIndex = dow - 1;

    // Se ├® segunda-feira e j├í temos dados na semana atual, salva e come├ºa nova
    if (weekdayIndex === 0 && currentWeek.length > 0) {
      // Preenche slots vazios no final da semana anterior
      while (currentWeek.length < 5) currentWeek.push(null);
      weeks.push(currentWeek);
      currentWeek = [];
    }

    // Preenche slots vazios no in├¡cio (ex: m├¬s come├ºa na quarta)
    while (currentWeek.length < weekdayIndex) currentWeek.push(null);

    const m = String(month).padStart(2, '0');
    const d = String(day).padStart(2, '0');
    currentWeek.push({ day, dateStr: `${year}-${m}-${d}` });
  }

  // Salva ├║ltima semana
  if (currentWeek.length > 0) {
    while (currentWeek.length < 5) currentWeek.push(null);
    weeks.push(currentWeek);
  }

  return weeks;
};

export const CardapioList: React.FC = () => {
  const now = new Date();
  const [currentMonth, setCurrentMonth] = useState(now.getMonth() + 1); // 1-12
  const [currentYear, setCurrentYear] = useState(now.getFullYear());
  const [cardapios, setCardapios] = useState<Cardapio[]>([]);
  const [fichas, setFichas] = useState<Ficha[]>([]);
  const [loading, setLoading] = useState(false);

  // Estados para Modal (Novo/Editar)
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalMode, setModalMode] = useState<'create' | 'edit'>('create');
  const [cardapioEmEdicao, setCardapioEmEdicao] = useState<Cardapio | null>(null);

  const [editData, setEditData] = useState('');
  const [editDescricao, setEditDescricao] = useState('');
  const [editFichaId, setEditFichaId] = useState('');
  const [editTiposEscola, setEditTiposEscola] = useState<string[]>([]);
  const [editIsFeriado, setEditIsFeriado] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Exclus├úo
  const [cardapioParaExcluir, setCardapioParaExcluir] = useState<Cardapio | null>(null);
  const [isDeleting, setIsDeleting] = useState(false);

  const { toast } = useToast();

  const fetchCardapios = async () => {
    setLoading(true);
    try {
      const data = await getCardapios(currentMonth, currentYear);
      setCardapios(data);
    } catch (error) {
      console.error('Erro ao buscar card├ípios:', error);
      toast({ variant: "destructive", title: "Erro", description: "N├úo foi poss├¡vel carregar os card├ípios." });
    } finally {
      setLoading(false);
    }
  };

  const fetchFichas = async () => {
    try {
      const data = await getFichas();
      setFichas(data);
    } catch (error) {
      console.error('Erro ao buscar fichas:', error);
    }
  };

  useEffect(() => { fetchFichas(); }, []);
  useEffect(() => { fetchCardapios(); }, [currentMonth, currentYear]);

  const isFeriado = (c: Cardapio) => c.isFeriado || c.is_feriado;
  const todayStr = getLocalToday();

  // Agrupa card├ípios por dateStr (YYYY-MM-DD)
  const cardapiosByDate = useMemo(() => {
    const map: Record<string, Cardapio[]> = {};
    cardapios.forEach((c) => {
      const key = toDateString(c.data_agendada);
      if (!map[key]) map[key] = [];
      map[key].push(c);
    });
    return map;
  }, [cardapios]);

  // Gera as semanas do m├¬s
  const weeks = useMemo(() => getWeeksOfMonth(currentYear, currentMonth), [currentYear, currentMonth]);

  // Navega├º├úo
  const handlePrevMonth = () => {
    if (currentMonth === 1) { setCurrentMonth(12); setCurrentYear((y) => y - 1); }
    else setCurrentMonth((m) => m - 1);
  };
  const handleNextMonth = () => {
    if (currentMonth === 12) { setCurrentMonth(1); setCurrentYear((y) => y + 1); }
    else setCurrentMonth((m) => m + 1);
  };

  // --- Handlers Modal ---
  const handleOpenCreate = (date?: string, template?: Cardapio) => {
    setModalMode('create');
    setCardapioEmEdicao(null);
    setEditData(date || '');
    setEditDescricao('');
    setEditFichaId(template?.fichaTecnicaId || template?.ficha_tecnica_id || '');
    // Se for um novo registro (sem template), seleciona todos por padr├úo. 
    // Se for clonagem (com template), usa o que veio do original.
    setEditTiposEscola(template?.tipos_escola || [...TIPOS_ESCOLA_OPTIONS]);
    setEditIsFeriado(template ? !!isFeriado(template) : false);
    setIsModalOpen(true);
  };

  const handleOpenEdit = (cardapio: Cardapio) => {
    setModalMode('edit');
    setCardapioEmEdicao(cardapio);
    setEditData(toDateString(cardapio.data_agendada));
    setEditDescricao(cardapio.descricao || '');
    setEditFichaId(cardapio.fichaTecnicaId || cardapio.ficha_tecnica_id || '');
    setEditTiposEscola(cardapio.tipos_escola || []);
    setEditIsFeriado(!!isFeriado(cardapio));
    setIsModalOpen(true);
  };

  const handleDuplicate = (cardapio: Cardapio) => {
    handleOpenCreate('', cardapio);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setCardapioEmEdicao(null);
  };

  const handleToggleTipoEscola = (tipo: string) => {
    setEditTiposEscola((prev) =>
      prev.includes(tipo) ? prev.filter((t) => t !== tipo) : [...prev, tipo]
    );
  };

  const handleSubmit = async () => {
    if (!editData || editTiposEscola.length === 0) {
      toast({ variant: "destructive", title: "Aten├º├úo", description: "Data e Tipos de Escola s├úo obrigat├│rios." });
      return;
    }
    if (!editIsFeriado && !editFichaId) {
      toast({ variant: "destructive", title: "Aten├º├úo", description: "Selecione uma Ficha T├®cnica ou marque como Feriado." });
      return;
    }

    setIsSubmitting(true);
    try {
      if (modalMode === 'create') {
        await createCardapio({
          date: editData,
          descricao: editDescricao || undefined,
          fichaId: editIsFeriado ? undefined : editFichaId,
          is_feriado: editIsFeriado,
          tipos_escola: editTiposEscola,
        });
        toast({ className: "bg-emerald-50 text-emerald-900 border-emerald-200", title: "Sucesso", description: "Card├ípio criado com sucesso." });
      } else if (cardapioEmEdicao) {
        await updateCardapio(cardapioEmEdicao.id, {
          data_agendada: `${editData}T12:00:00.000Z`,
          descricao: editDescricao || undefined,
          ficha_tecnica_id: editIsFeriado ? null : editFichaId,
          tipos_escola: editTiposEscola,
          isFeriado: editIsFeriado,
        });
        toast({ className: "bg-emerald-50 text-emerald-900 border-emerald-200", title: "Sucesso", description: "Card├ípio atualizado." });
      }
      handleCloseModal();
      fetchCardapios();
    } catch (error: any) {
      console.error('Erro ao salvar card├ípio:', error);
      toast({ variant: "destructive", title: "Erro", description: error.response?.data?.error || "Erro ao salvar." });
    } finally {
      setIsSubmitting(false);
    }
  };

  // --- Exclus├úo ---
  const handleConfirmDelete = async () => {
    if (!cardapioParaExcluir) return;
    setIsDeleting(true);
    try {
      await deleteCardapio(cardapioParaExcluir.id);
      toast({ className: "bg-emerald-50 text-emerald-900 border-emerald-200", title: "Sucesso", description: "Card├ípio exclu├¡do." });
      fetchCardapios();
    } catch (error: any) {
      console.error('Erro ao excluir card├ípio:', error);
      toast({ variant: "destructive", title: "Erro", description: error.response?.data?.error || "Erro ao excluir." });
    } finally {
      setIsDeleting(false);
      setCardapioParaExcluir(null);
    }
  };

  return (
    <div className="p-8 max-w-7xl mx-auto flex flex-col gap-6">
      {/* Cabe├ºalho */}
      <div className="flex justify-between items-start">
        <div>
          <h1 className="text-3xl font-bold text-foreground flex items-center gap-3">
            <CalendarDays className="h-8 w-8 text-blue-600" />
            Planejamento de Card├ípio
          </h1>
          <p className="text-muted-foreground mt-1">Grade semanal de refei├º├Áes por m├¬s.</p>
        </div>
      </div>

      {/* Navega├º├úo M├¬s/Ano */}
      <div className="flex items-center justify-center gap-4 bg-white rounded-lg border border-slate-200 shadow-sm p-3">
        <Button variant="outline" size="sm" onClick={handlePrevMonth} className="h-9 w-9 p-0">
          <ChevronLeft className="h-4 w-4" />
        </Button>
        <h2 className="text-xl font-bold text-slate-800 min-w-[220px] text-center">
          {MESES[currentMonth - 1]} de {currentYear}
        </h2>
        <Button variant="outline" size="sm" onClick={handleNextMonth} className="h-9 w-9 p-0">
          <ChevronRight className="h-4 w-4" />
        </Button>
      </div>

      {/* Grade Semanal */}
      {loading ? (
        <div className="py-12 text-center text-slate-500">Carregando card├ípios...</div>
      ) : (
        <div className="flex flex-col gap-1">
          {/* Cabe├ºalho da grade */}
          <div className="grid grid-cols-5 gap-1">
            {DIAS_SEMANA.map((dia) => (
              <div key={dia} className="bg-slate-800 text-white text-center text-sm font-semibold py-2.5 rounded-t-md">
                {dia}
              </div>
            ))}
          </div>

          {/* Semanas */}
          {weeks.map((week, weekIdx) => (
            <div key={weekIdx} className="grid grid-cols-5 gap-1">
              {week.map((slot, dayIdx) => {
                if (!slot) {
                  return <div key={dayIdx} className="min-h-[120px] bg-slate-50 rounded-md border border-slate-100" />;
                }

                const dayCardapios = cardapiosByDate[slot.dateStr] || [];
                const isToday = slot.dateStr === todayStr;
                const isPast = slot.dateStr < todayStr;

                return (
                  <div
                    key={dayIdx}
                    onClick={() => handleOpenCreate(slot.dateStr)}
                    className={`min-h-[120px] rounded-md border p-2 flex flex-col gap-1.5 transition-colors cursor-pointer hover:bg-slate-50 group ${
                      isToday
                        ? 'bg-orange-50 border-orange-300 ring-2 ring-orange-200'
                        : isPast
                        ? 'bg-slate-50 border-slate-200'
                        : 'bg-white border-slate-200'
                    }`}
                  >
                    {/* N├║mero do dia */}
                    <div className="flex justify-between items-center h-7">
                      <span className={`text-xs font-bold ${isToday ? 'text-orange-700' : isPast ? 'text-slate-400' : 'text-slate-600'}`}>
                        {slot.day}
                      </span>
                      <div className="flex items-center gap-1">
                        {isToday && (
                          <span className="text-[10px] font-semibold bg-orange-600 text-white px-1.5 py-0.5 rounded">HOJE</span>
                        )}
                        <button
                          onClick={(e) => { e.stopPropagation(); handleOpenCreate(slot.dateStr); }}
                          className="opacity-0 group-hover:opacity-100 transition-opacity text-slate-400 hover:text-blue-600 hover:bg-slate-100 p-1 rounded-md"
                          title="Adicionar card├ípio"
                        >
                          <Plus className="h-3.5 w-3.5" />
                        </button>
                      </div>
                    </div>

                    {/* Cards dos card├ípios do dia */}
                    {dayCardapios.length === 0 ? (
                      <div className="flex-1 flex items-center justify-center">
                        <span className="text-[10px] text-slate-300 italic">Sem agendamento</span>
                      </div>
                    ) : (
                      dayCardapios.map((cardapio) => (
                        <Card
                          key={cardapio.id}
                          className={`shadow-none border ${
                            isFeriado(cardapio)
                              ? 'bg-red-50 border-red-200'
                              : 'bg-blue-50 border-blue-200'
                          }`}
                        >
                          <CardContent className="p-2">
                            {isFeriado(cardapio) ? (
                              <p className="text-xs font-bold text-red-700 text-center">FERIADO / RECESSO</p>
                            ) : (
                              <>
                                <p className="text-xs font-semibold text-slate-800 leading-tight truncate" title={cardapio.ficha?.name}>
                                  {cardapio.ficha?.name || 'Ficha?'}
                                </p>
                                {cardapio.tipos_escola && cardapio.tipos_escola.length > 0 && (
                                  <div className="flex flex-wrap gap-0.5 mt-1">
                                    {cardapio.tipos_escola.map((t) => (
                                      <span key={t} className="text-[9px] bg-blue-100 text-blue-700 rounded px-1 py-px font-medium">
                                        {t}
                                      </span>
                                    ))}
                                  </div>
                                )}
                              </>
                            )}
                            {/* A├º├Áes */}
                            <div className="flex justify-end gap-1 mt-1.5">
                              <button
                                onClick={(e) => { e.stopPropagation(); handleDuplicate(cardapio); }}
                                className="p-0.5 rounded hover:bg-amber-100 text-slate-400 hover:text-amber-600 transition-colors"
                                title="Duplicar"
                              >
                                <Copy className="h-3 w-3" />
                              </button>
                              <button
                                onClick={(e) => { e.stopPropagation(); handleOpenEdit(cardapio); }}
                                className="p-0.5 rounded hover:bg-blue-100 text-slate-400 hover:text-blue-600 transition-colors"
                                title="Editar"
                              >
                                <Pencil className="h-3 w-3" />
                              </button>
                              <button
                                onClick={(e) => { e.stopPropagation(); setCardapioParaExcluir(cardapio); }}
                                className="p-0.5 rounded hover:bg-red-100 text-slate-400 hover:text-red-600 transition-colors"
                                title="Excluir"
                              >
                                <Trash2 className="h-3 w-3" />
                              </button>
                            </div>
                          </CardContent>
                        </Card>
                      ))
                    )}
                  </div>
                );
              })}
            </div>
          ))}
        </div>
      )}

      {/* ========== Modal ├Ünico (Novo/Editar) ========== */}
      <Dialog open={isModalOpen} onOpenChange={(open) => !open && handleCloseModal()}>
        <DialogContent 
          className="sm:max-w-[520px] max-h-[85vh] overflow-y-auto bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800 opacity-100"
          onPointerDownOutside={(e) => e.preventDefault()}
          onEscapeKeyDown={(e) => e.preventDefault()}
        >
          <DialogHeader>
            <DialogTitle className="text-slate-900 dark:text-slate-100">
              {modalMode === 'create' ? 'Novo Card├ípio' : 'Editar Card├ípio'}
            </DialogTitle>
            <DialogDescription className="text-slate-500 dark:text-slate-400">
              {modalMode === 'create' ? 'Agende uma nova refei├º├úo para a rede.' : 'Ajuste os dados do agendamento.'}
            </DialogDescription>
          </DialogHeader>

          {modalMode === 'edit' && editData < todayStr && (
            <div className="flex items-start gap-3 p-3 rounded-md bg-amber-50 border border-amber-200 text-amber-800 text-sm">
              <AlertTriangle className="h-5 w-5 text-amber-500 mt-0.5 flex-shrink-0" />
              <div>
                <p className="font-semibold">Aviso Operacional</p>
                <p className="text-amber-700 text-xs mt-0.5">
                  Voc├¬ est├í alterando um card├ípio do passado. O estoque j├í foi processado para este dia.
                </p>
              </div>
            </div>
          )}

          <div className="flex flex-col gap-4 py-4">
            <div className="flex flex-col gap-2">
              <Label className="text-slate-900 dark:text-slate-200 font-semibold">Data Agendada</Label>
              <Input type="date" value={editData} onChange={(e) => setEditData(e.target.value)} />
            </div>
            <div className="flex flex-col gap-2">
              <Label className="text-slate-900 dark:text-slate-200 font-semibold">Descri├º├úo (opcional)</Label>
              <Input value={editDescricao} onChange={(e) => setEditDescricao(e.target.value)} placeholder="Ex: Card├ípio especial" />
            </div>
            <div className="flex items-center gap-3">
              <input type="checkbox" id="editIsFeriado" checked={editIsFeriado} onChange={(e) => setEditIsFeriado(e.target.checked)} className="h-4 w-4 rounded border-slate-300" />
              <Label htmlFor="editIsFeriado" className="text-slate-900 dark:text-slate-200 font-semibold cursor-pointer">Feriado / Facultativo</Label>
            </div>
            {!editIsFeriado && (
              <div className="flex flex-col gap-2">
                <Label className="text-slate-900 dark:text-slate-200 font-semibold">Ficha T├®cnica</Label>
                <Select value={editFichaId} onValueChange={setEditFichaId}>
                  <SelectTrigger className="bg-white dark:bg-slate-950 text-slate-900 dark:text-slate-100"><SelectValue placeholder="Selecione a ficha" /></SelectTrigger>
                  <SelectContent className="bg-white dark:bg-slate-950 border-slate-200 dark:border-slate-800">
                    {fichas.map((f) => (
                      <SelectItem key={f.id} value={f.id} className="text-slate-900 dark:text-slate-100 focus:bg-slate-100 dark:focus:bg-slate-800">{f.name} {f.type ? `(${f.type})` : ''}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            )}
            <div className="flex flex-col gap-2">
              <Label className="text-slate-900 dark:text-slate-200 font-semibold">Tipos de Escola</Label>
              <div className="flex flex-wrap gap-2">
                {TIPOS_ESCOLA_OPTIONS.map((tipo) => (
                  <button key={tipo} type="button" onClick={() => handleToggleTipoEscola(tipo)} className={`px-3 py-1.5 rounded-md text-xs font-medium border transition-colors ${editTiposEscola.includes(tipo) ? 'bg-orange-100 text-orange-800 border-orange-300' : 'bg-slate-50 text-slate-600 border-slate-200 hover:bg-slate-100'}`}>{tipo}</button>
                ))}
              </div>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={handleCloseModal} disabled={isSubmitting}>Cancelar</Button>
            <Button onClick={handleSubmit} disabled={isSubmitting} className="bg-blue-600 hover:bg-blue-700 text-white">
              {isSubmitting ? 'Salvando...' : modalMode === 'create' ? 'Criar Card├ípio' : 'Salvar Altera├º├Áes'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* ========== Modal de Exclus├úo (DELETE) ========== */}
      <AlertDialog open={!!cardapioParaExcluir} onOpenChange={(open) => !open && setCardapioParaExcluir(null)}>
        <AlertDialogContent className="bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800 opacity-100">
          <AlertDialogHeader>
            <AlertDialogTitle className="text-slate-900 dark:text-slate-100">
              Excluir card├ípio de {cardapioParaExcluir ? new Date(cardapioParaExcluir.data_agendada).toLocaleDateString('pt-BR', { timeZone: 'UTC' }) : ''}?
            </AlertDialogTitle>
            <AlertDialogDescription className="text-slate-500 dark:text-slate-400">Esta a├º├úo remover├í permanentemente este agendamento.</AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel disabled={isDeleting} className="text-slate-900 dark:text-slate-100 border-slate-200 dark:border-slate-800">Cancelar</AlertDialogCancel>
            <AlertDialogAction onClick={(e) => { e.preventDefault(); handleConfirmDelete(); }} disabled={isDeleting} className="bg-red-600 hover:bg-red-700 text-white">{isDeleting ? 'Excluindo...' : 'Sim, Excluir'}</AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Card, CardHeader, CardTitle, CardDescription, CardContent } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter, DialogDescription } from '@/components/ui/dialog';
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from '@/components/ui/alert-dialog';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Pencil, Trash2, Plus } from 'lucide-react';
import { useToast } from '@/hooks/use-toast';
import { api } from '../../services/api';

interface Item {
  id: string;
  name: string;
  baseUnit: string;
  packagingSize: number;
}

export const ItemsList: React.FC = () => {
  const [items, setItems] = useState<Item[]>([]);
  const [loading, setLoading] = useState(false);

  // States para Cria├º├úo
  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
  const [newName, setNewName] = useState('');
  const [newBaseUnit, setNewBaseUnit] = useState('');
  const [newPackagingSize, setNewPackagingSize] = useState<number | ''>('');
  const [isSubmittingCreate, setIsSubmittingCreate] = useState(false);

  // States para Edi├º├úo
  const [itemEmEdicao, setItemEmEdicao] = useState<Item | null>(null);
  const [editName, setEditName] = useState('');
  const [editBaseUnit, setEditBaseUnit] = useState('');
  const [editPackagingSize, setEditPackagingSize] = useState<number | ''>('');
  const [isSubmittingEdit, setIsSubmittingEdit] = useState(false);

  // States para Exclus├úo
  const [itemParaExcluir, setItemParaExcluir] = useState<Item | null>(null);
  const [isDeleting, setIsDeleting] = useState(false);

  const { toast } = useToast();

  const fetchItems = async () => {
    setLoading(true);
    try {
      const response = await api.get('/items');
      setItems(response.data);
    } catch (error) {
      console.error('Erro ao buscar itens:', error);
      toast({
        variant: "destructive",
        title: "Erro de Conex├úo",
        description: "N├úo foi poss├¡vel carregar o cat├ílogo de itens.",
      });
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchItems();
  }, []);

  // --- Handlers de Cria├º├úo ---
  const handleOpenCreate = () => {
    setIsCreateModalOpen(true);
    setNewName('');
    setNewBaseUnit('');
    setNewPackagingSize('');
  };

  const handleCloseCreate = () => {
    setIsCreateModalOpen(false);
  };

  const handleSubmitCreate = async () => {
    if (!newName || !newBaseUnit || !newPackagingSize) {
      toast({
        variant: "destructive",
        title: "Aten├º├úo",
        description: "Todos os campos s├úo obrigat├│rios.",
      });
      return;
    }

    const parsedSize = parseFloat(String(newPackagingSize).replace(',', '.'));
    if (isNaN(parsedSize) || parsedSize <= 0) {
      toast({
        variant: "destructive",
        title: "Aten├º├úo",
        description: "O tamanho da embalagem deve ser um n├║mero maior que zero.",
      });
      return;
    }

    setIsSubmittingCreate(true);
    try {
      await api.post('/items', {
        name: newName,
        base_unit: newBaseUnit,
        packaging_size: parsedSize
      });

      toast({
        className: "bg-emerald-50 text-emerald-900 border-emerald-200",
        title: "Sucesso",
        description: "Item criado com sucesso.",
      });

      handleCloseCreate();
      fetchItems();
    } catch (error: any) {
      console.error('Erro ao criar:', error);
      toast({
        variant: "destructive",
        title: "Erro na Cria├º├úo",
        description: error.response?.data?.error || "Erro ao cadastrar o item. Verifique os dados e tente novamente.",
      });
    } finally {
      setIsSubmittingCreate(false);
    }
  };

  // --- Handlers de Edi├º├úo ---
  const handleOpenEdit = (item: Item) => {
    setItemEmEdicao(item);
    setEditName(item.name);
    setEditBaseUnit(item.baseUnit);
    setEditPackagingSize(item.packagingSize);
  };

  const handleCloseEdit = () => {
    setItemEmEdicao(null);
  };

  const handleSubmitEdit = async () => {
    if (!itemEmEdicao) return;

    if (!editName || !editBaseUnit || !editPackagingSize) {
      toast({
        variant: "destructive",
        title: "Aten├º├úo",
        description: "Todos os campos s├úo obrigat├│rios.",
      });
      return;
    }

    if (Number(editPackagingSize) <= 0) {
      toast({
        variant: "destructive",
        title: "Aten├º├úo",
        description: "O tamanho da embalagem deve ser maior que zero.",
      });
      return;
    }

    setIsSubmittingEdit(true);
    try {
      await api.put(`/items/${itemEmEdicao.id}`, {
        name: editName,
        baseUnit: editBaseUnit,
        packagingSize: Number(editPackagingSize)
      });

      toast({
        title: "Sucesso",
        description: "Item atualizado com sucesso.",
      });

      handleCloseEdit();
      fetchItems();
    } catch (error: any) {
      console.error('Erro ao editar:', error);
      toast({
        variant: "destructive",
        title: "Erro na Edi├º├úo",
        description: error.response?.data?.error || "Erro interno ao atualizar item.",
      });
    } finally {
      setIsSubmittingEdit(false);
    }
  };

  // --- Handlers de Exclus├úo ---
  const handleOpenDelete = (item: Item) => {
    setItemParaExcluir(item);
  };

  const handleCloseDelete = () => {
    setItemParaExcluir(null);
  };

  const handleConfirmDelete = async () => {
    if (!itemParaExcluir) return;

    setIsDeleting(true);
    try {
      await api.delete(`/items/${itemParaExcluir.id}`);

      toast({
        className: "bg-emerald-50 text-emerald-900 border-emerald-200",
        title: "Sucesso",
        description: "Item exclu├¡do com sucesso.",
      });

      handleCloseDelete();
      fetchItems();
    } catch (error: any) {
      console.error('Erro ao excluir:', error);
      toast({
        variant: "destructive",
        title: "Opera├º├úo Bloqueada",
        description: error.response?.data?.error || "Erro interno ao excluir item.",
      });
    } finally {
      setIsDeleting(false);
      handleCloseDelete();
    }
  };

  return (
    <div className="p-8 max-w-6xl mx-auto flex flex-col gap-6">
      <div className="flex justify-between items-start">
        <div>
          <h1 className="text-3xl font-bold text-foreground">Cat├ílogo de Itens</h1>
          <p className="text-muted-foreground mt-1">Gerencie os ingredientes e insumos log├¡sticos do sistema.</p>
        </div>
        <Button onClick={handleOpenCreate} className="bg-blue-600 hover:bg-blue-700 text-white">
          <Plus className="mr-2 h-4 w-4" />
          Novo Item
        </Button>
      </div>

      <Card className="shadow-sm border-slate-200">
        <CardHeader>
          <CardTitle className="text-xl text-slate-700">Itens Cadastrados</CardTitle>
          <CardDescription>
            Listagem do cat├ílogo. Altera├º├Áes impactam o cat├ílogo de receitas e estoques f├¡sicos.
          </CardDescription>
        </CardHeader>
        <CardContent>
          {loading ? (
            <div className="py-8 text-center text-slate-500">Carregando itens...</div>
          ) : (
            <Table>
              <TableHeader className="bg-slate-50">
                <TableRow>
                  <TableHead className="font-semibold text-slate-700 px-6 py-4">Nome do Item</TableHead>
                  <TableHead className="font-semibold text-slate-700 px-6 py-4">Unidade Base</TableHead>
                  <TableHead className="font-semibold text-slate-700 px-6 py-4">Tamanho da Embalagem</TableHead>
                  <TableHead className="text-right font-semibold text-slate-700 px-6 py-4">A├º├Áes</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {items.length === 0 ? (
                  <TableRow>
                    <TableCell colSpan={4} className="text-center py-8 text-slate-500">
                      Nenhum item encontrado no cat├ílogo.
                    </TableCell>
                  </TableRow>
                ) : (
                  items.map((item) => (
                    <TableRow key={item.id} className="hover:bg-slate-50 transition-colors">
                      <TableCell className="font-medium text-slate-800 px-6 py-4">{item.name}</TableCell>
                      <TableCell className="text-slate-600 px-6 py-4">{item.baseUnit}</TableCell>
                      <TableCell className="text-slate-600 px-6 py-4">{item.packagingSize}</TableCell>
                      <TableCell className="text-right px-6 py-4">
                        <div className="flex justify-end gap-2">
                          <Button 
                            variant="outline" 
                            size="sm" 
                            className="h-8 w-8 p-0 text-slate-500 hover:text-blue-600 hover:bg-blue-50 border-slate-200"
                            onClick={() => handleOpenEdit(item)}
                          >
                            <Pencil className="h-4 w-4" />
                          </Button>
                          <Button 
                            variant="outline" 
                            size="sm" 
                            className="h-8 w-8 p-0 text-slate-500 hover:text-red-600 hover:bg-red-50 border-slate-200"
                            onClick={() => handleOpenDelete(item)}
                          >
                            <Trash2 className="h-4 w-4" />
                          </Button>
                        </div>
                      </TableCell>
                    </TableRow>
                  ))
                )}
              </TableBody>
            </Table>
          )}
        </CardContent>
      </Card>

      <Dialog open={isCreateModalOpen} onOpenChange={(open) => !open && handleCloseCreate()}>
        <DialogContent 
          className="sm:max-w-[425px] bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800 opacity-100"
          onPointerDownOutside={(e) => e.preventDefault()}
          onEscapeKeyDown={(e) => e.preventDefault()}
        >
          <DialogHeader>
            <DialogTitle className="text-slate-900 dark:text-slate-100">Criar Novo Item</DialogTitle>
            <DialogDescription className="text-slate-500 dark:text-slate-400">
              Preencha os dados do novo item a ser inserido no cat├ílogo.
            </DialogDescription>
          </DialogHeader>
