import {
  getConsumosFixosByEscola,
  saveConsumoFixo,
  deleteConsumoFixo,
  type ConsumoFixo
} from '@/services/api/consumos';

export const ConsumosFixosList = () => {
  const [escolas, setEscolas] = useState<Escola[]>([]);
  const [items, setItems] = useState<Item[]>([]);
  const [selectedEscolaId, setSelectedEscolaId] = useState<string>("");
  const [consumos, setConsumos] = useState<ConsumoFixo[]>([]);
  const [loading, setLoading] = useState(false);
  const { toast } = useToast();

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingConsumo, setEditingConsumo] = useState<ConsumoFixo | null>(null);
  const [selectedItemId, setSelectedItemId] = useState<string>("");
  const [quantidade, setQuantidade] = useState<string>("");
  const [isSubmitting, setIsSubmitting] = useState(false);

  useEffect(() => {
    const loadInitialData = async () => {
      try {
        const [escolasData, itemsData] = await Promise.all([
          getEscolas(),
          getItems()
        ]);
        setEscolas(escolasData);
        setItems(itemsData);
      } catch (error) {
        toast({
          variant: "destructive",
          title: "Erro",
          description: "N├úo foi poss├¡vel carregar os dados iniciais."
        });
      }
    };
    loadInitialData();
  }, []);

  useEffect(() => {
    if (selectedEscolaId) {
      fetchConsumos();
    } else {
      setConsumos([]);
    }
  }, [selectedEscolaId]);

  const fetchConsumos = async () => {
    if (!selectedEscolaId) return;
    setLoading(true);
    try {
      const data = await getConsumosFixosByEscola(selectedEscolaId);
      setConsumos(data);
    } catch (error) {
      toast({
        variant: "destructive",
        title: "Erro",
        description: "N├úo foi poss├¡vel carregar os consumos fixos."
      });
    } finally {
      setLoading(false);
    }
  };

  const handleOpenModal = (consumo?: ConsumoFixo) => {
    if (consumo) {
      setEditingConsumo(consumo);
      setSelectedItemId(consumo.itemId);
      setQuantidade(String(consumo.quantidadeDiaria));
    } else {
      setEditingConsumo(null);
      setSelectedItemId("");
      setQuantidade("");
    }
    setIsModalOpen(true);
  };

  const handleSave = async () => {
    if (!selectedEscolaId || !selectedItemId || !quantidade) {
      toast({
        variant: "destructive",
        title: "Aten├º├úo",
        description: "Preencha todos os campos."
      });
      return;
    }

    setIsSubmitting(true);
    try {
      await saveConsumoFixo(selectedEscolaId, {
        itemId: selectedItemId,
        quantidadeDiaria: parseFloat(quantidade)
      });
      toast({
        title: "Sucesso",
        description: "Consumo fixo salvo com sucesso.",
        className: "bg-emerald-50 text-emerald-900 border-emerald-200"
      });
      setIsModalOpen(false);
      fetchConsumos();
    } catch (error) {
      toast({
        variant: "destructive",
        title: "Erro",
        description: "N├úo foi poss├¡vel salvar o consumo fixo."
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDelete = async (id: string) => {
    try {
      await deleteConsumoFixo(id);
      toast({
        title: "Removido",
        description: "Consumo fixo removido com sucesso."
      });
      fetchConsumos();
    } catch (error) {
      toast({
        variant: "destructive",
        title: "Erro",
        description: "Erro ao remover o item."
      });
    }
  };

  return (
    <div className="p-8 max-w-6xl mx-auto space-y-8 animate-in fade-in duration-500">
      {/* Header & Escola Selector */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <div>
          <h1 className="text-3xl font-bold text-slate-900 flex items-center gap-3">
            <ClipboardList className="h-8 w-8 text-blue-600" />
            Consumo Fixo Di├írio
          </h1>
          <p className="text-slate-500 mt-1 text-sm font-medium">Itens consumidos diariamente independente do card├ípio.</p>
        </div>

        <div className="w-full md:w-80 space-y-2">
          <Label className="text-xs font-bold uppercase tracking-wider text-slate-400 px-1">Selecionar Unidade Escolar</Label>
          <Select value={selectedEscolaId} onValueChange={setSelectedEscolaId}>
            <SelectTrigger className="h-11 bg-white border-slate-200 shadow-sm focus:ring-2 focus:ring-blue-500/20 transition-all">
              <SelectValue placeholder="Escolha uma escola..." />
            </SelectTrigger>
            <SelectContent>
              {escolas.map((escola) => (
                <SelectItem key={escola.id} value={escola.id}>
                  {escola.name}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
      </div>

      {!selectedEscolaId ? (
        <Card className="border-dashed border-2 bg-slate-50/50 shadow-none">
          <CardContent className="flex flex-col items-center justify-center py-24 text-center">
            <div className="h-20 w-20 bg-blue-100/50 rounded-full flex items-center justify-center mb-6 animate-pulse">
              <School className="h-10 w-10 text-blue-600" />
            </div>
            <h3 className="text-xl font-bold text-slate-900">Selecione uma Escola</h3>
            <p className="text-slate-500 max-w-sm mt-2 font-medium">
              Para visualizar ou configurar o consumo fixo, escolha uma unidade escolar no seletor acima.
            </p>
          </CardContent>
        </Card>
      ) : (
        <Card className="shadow-md border-slate-200 overflow-hidden bg-white">
          <CardHeader className="flex flex-row items-center justify-between border-b border-slate-100 bg-slate-50/30 px-6 py-6">
            <div className="space-y-1">
              <CardTitle className="text-xl text-slate-800 font-bold">Itens em Consumo</CardTitle>
              <CardDescription className="text-slate-500 font-medium">Insumos com sa├¡da autom├ítica para a unidade selecionada.</CardDescription>
            </div>
            <Button onClick={() => handleOpenModal()} className="bg-blue-600 hover:bg-blue-700 text-white shadow-lg shadow-blue-500/20 px-6 font-semibold">
              <Plus className="mr-2 h-4 w-4" /> Adicionar Item
            </Button>
          </CardHeader>
          <CardContent className="p-0">
            {loading ? (
              <div className="py-20 text-center flex flex-col items-center gap-3">
                <div className="h-8 w-8 border-4 border-blue-600 border-t-transparent rounded-full animate-spin" />
                <span className="text-slate-400 font-medium">Buscando configura├º├Áes...</span>
              </div>
            ) : consumos.length === 0 ? (
              <div className="py-20 text-center flex flex-col items-center gap-4">
                <div className="h-12 w-12 bg-slate-100 rounded-full flex items-center justify-center">
                  <AlertCircle className="h-6 w-6 text-slate-400" />
                </div>
                <div className="space-y-1">
                  <p className="text-slate-800 font-bold">Nenhum consumo configurado</p>
                  <p className="text-slate-400 text-sm">Adicione o primeiro item para esta escola usando o bot├úo acima.</p>
                </div>
              </div>
            ) : (
              <div className="overflow-x-auto">
                <Table>
                  <TableHeader className="bg-slate-50/80">
                    <TableRow>
                      <TableHead className="font-bold text-slate-700 px-8 py-4 h-14">Nome do Item</TableHead>
                      <TableHead className="font-bold text-slate-700 text-center h-14">Unidade</TableHead>
                      <TableHead className="font-bold text-slate-700 text-center h-14">Quantidade Di├íria</TableHead>
                      <TableHead className="font-bold text-slate-700 text-right px-8 h-14">A├º├Áes</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {consumos.map((c) => (
                      <TableRow key={c.id} className="hover:bg-slate-50/80 transition-all border-b border-slate-100">
                        <TableCell className="px-8 py-5 font-semibold text-slate-800">{c.item.name}</TableCell>
                        <TableCell className="text-center">
                          <span className="px-2 py-1 bg-slate-100 text-slate-600 rounded text-[10px] font-bold uppercase tracking-wider">
                            {c.item.baseUnit || 'un'}
                          </span>
                        </TableCell>
                        <TableCell className="text-center">
                          <div className="inline-flex items-center justify-center px-4 py-1.5 bg-blue-50 text-blue-700 rounded-lg text-sm font-black border border-blue-100 shadow-sm">
                            {c.quantidadeDiaria}
                          </div>
                        </TableCell>
                        <TableCell className="text-right px-8 py-5">
                          <div className="flex justify-end gap-3">
                            <Button
                              variant="outline"
                              size="sm"
                              className="h-9 px-3 text-slate-600 hover:text-blue-600 hover:bg-blue-50 border-slate-200 hover:border-blue-200 transition-all"
                              onClick={() => handleOpenModal(c)}
                            >
                              <Pencil className="h-4 w-4 mr-2" />
                              Editar
                            </Button>
                            <Button
                              variant="outline"
                              size="sm"
                              className="h-9 px-3 text-slate-400 hover:text-red-600 hover:bg-red-50 border-slate-200 hover:border-red-200 transition-all"
                              onClick={() => handleDelete(c.id)}
                            >
                              <Trash2 className="h-4 w-4" />
                            </Button>
                          </div>
                        </TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </div>
            )}
          </CardContent>
        </Card>
      )}

      <Dialog open={isModalOpen} onOpenChange={setIsModalOpen}>
        <DialogContent
          className="sm:max-w-[480px] p-0 overflow-hidden rounded-2xl border-none shadow-2xl"
          onPointerDownOutside={(e) => e.preventDefault()}
          onEscapeKeyDown={(e) => e.preventDefault()}
        >
          <DialogHeader className="bg-slate-900 text-white p-8">
            <DialogTitle className="text-2xl font-bold">{editingConsumo ? 'Editar' : 'Novo'} Consumo Fixo</DialogTitle>
            <DialogDescription className="text-slate-400 text-base mt-2">
              Defina a quantidade de sa├¡da autom├ítica por dia letivo para esta unidade.
            </DialogDescription>
          </DialogHeader>

          <div className="p-8 space-y-6 bg-white">
            <div className="space-y-2.5">
              <Label className="text-sm font-bold text-slate-700 ml-1">Item do Cat├ílogo</Label>
              <Select
                value={selectedItemId}
                onValueChange={setSelectedItemId}
                disabled={!!editingConsumo}
              >
                <SelectTrigger className="h-12 bg-slate-50 border-slate-200 focus:ring-2 focus:ring-blue-500/20">
                  <SelectValue placeholder="Selecione um produto..." />
                </SelectTrigger>
                <SelectContent className="max-h-60">
                  {items.map((item) => (
                    <SelectItem key={item.id} value={item.id} className="py-3">
                      {item.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div className="space-y-2.5">
              <Label className="text-sm font-bold text-slate-700 ml-1">Quantidade Di├íria</Label>
              <div className="relative">
                <Input
                  type="number"
                  step="0.01"
                  placeholder="Ex: 0.5"
                  value={quantidade}
                  onChange={(e) => setQuantidade(e.target.value)}
                  className="h-12 bg-slate-50 border-slate-200 pl-4 pr-12 font-bold text-lg focus:ring-2 focus:ring-blue-500/20"
                />
                <div className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 font-bold text-xs uppercase tracking-widest">
                  Unid.
                </div>
              </div>
              <p className="text-[11px] text-slate-400 italic ml-1">* Use ponto para decimais (ex: 1.5)</p>
            </div>
          </div>

          <DialogFooter className="bg-slate-50 p-6 flex flex-row gap-3 border-t border-slate-100">
            <Button variant="ghost" onClick={() => setIsModalOpen(false)} className="flex-1 font-bold text-slate-500 hover:bg-slate-200">
              Cancelar
            </Button>
            <Button
              onClick={handleSave}
              className="flex-1 bg-blue-600 hover:bg-blue-700 text-white font-bold h-11 shadow-lg shadow-blue-500/20"
              disabled={isSubmitting}
            >
              {isSubmitting ? 'Processando...' : editingConsumo ? 'Atualizar' : 'Confirmar'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
};

import { useEffect, useState } from 'react';
import {
  Cpu,
  AlertTriangle,
  Plus,
  Filter,
  ShieldAlert,
  School,
  Clock,
  PackageSearch
} from 'lucide-react';
import { Card, CardHeader, CardTitle, CardContent, CardDescription } from '@/components/ui/card';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow
} from '@/components/ui/table';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue
} from '@/components/ui/select';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Button } from '@/components/ui/button';
import { api } from '../services/api';
import { format, differenceInDays } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { Badge } from '@/components/ui/badge';
import { useToast } from '@/hooks/use-toast';

interface DashboardData {
  totalEscolas: number;
  totalReceitas: number;
  alertasEstoque: {
    id: string;
    quantidade: number;
    escola: { name: string };
    item: { name: string; baseUnit: string };
  }[];
  historicoMotor: {
    id: string;
    dataProcessamento: string;
    executadoEm: string;
    status: string;
    resumo: string | null;
  }[];
  alertasRemanejamento: {
    id: string;
    quantidadeRisco: number;
    dataVencimento: string | null;
    status: string;
    escola: { name: string };
    item: { name: string; baseUnit: string };
  }[];
  escolasLista: {
    id: string;
    name: string;
    type: string;
  }[];
}

interface Escola {
  id: string;
  name: string;
}

interface Item {
  id: string;
  name: string;
  baseUnit: string;
}

export const Dashboard: React.FC = () => {
  const [data, setData] = useState<DashboardData | null>(null);
  const [loading, setLoading] = useState<boolean>(true);
  const [escolas, setEscolas] = useState<Escola[]>([]);
  const [items, setItems] = useState<Item[]>([]);
  const [escolaFiltro, setEscolaFiltro] = useState<string>("all");
  const [abaAtiva, setAbaAtiva] = useState<string | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [totalRestricoes, setTotalRestricoes] = useState<number>(0);
  const { toast } = useToast();

  // Form states
  const [newAlert, setNewAlert] = useState({
    escolaId: '',
    itemId: '',
    quantidadeRisco: '',
    dataVencimento: ''
  });

  const fetchDashboard = async () => {
    setLoading(true);
    try {
      const url = `/dashboard/resumo${escolaFiltro !== "all" ? `?escolaId=${escolaFiltro}` : ''}`;
      const response = await api.get<DashboardData>(url);
      setData(response.data);
    } catch (error) {
      console.error('Erro ao buscar resumo do dashboard:', error);
    } finally {
      setLoading(false);
    }
  };

  const carregarMetricaDietas = async () => {
    try {
      const url = escolaFiltro === "all" ? '/dietas/demandas' : `/dietas/demandas?escolaId=${escolaFiltro}`;
      const res = await api.get(url, { headers: { Authorization: `Bearer ${localStorage.getItem('token')}` } });
      const total = (res.data || []).reduce((acc: number, demanda: any) => acc + Number(demanda.quantidade), 0);
      setTotalRestricoes(total);
    } catch (error) {
      console.error('Erro ao carregar m├®trica de dietas:', error);
    }
  };

  useEffect(() => {
    fetchDashboard();
    carregarMetricaDietas();
  }, [escolaFiltro]);

  useEffect(() => {
    // Prefetch for modal and filters
    api.get('/escolas').then(res => setEscolas(res.data));
    api.get('/items').then(res => setItems(res.data));
  }, []);

  const handleCreateAlert = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    try {
      await api.post('/alertas', newAlert);
      toast({
        title: "Alerta Criado!",
        description: "O lembrete de remanejamento foi registrado no painel.",
        className: "bg-amber-50 text-amber-900 border-amber-200"
      });
      setIsModalOpen(false);
      setNewAlert({ escolaId: '', itemId: '', quantidadeRisco: '', dataVencimento: '' });
      fetchDashboard();
    } catch (error) {
      toast({
        variant: "destructive",
        title: "Erro ao criar",
        description: "N├úo foi poss├¡vel registrar o alerta."
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleResolveAlert = async (id: string) => {
    try {
      await api.put(`/alertas/${id}/resolver`);
      toast({
        title: "Resolvido!",
        description: "O item foi marcado como remanejado/resolvido.",
        className: "bg-emerald-50 text-emerald-900 border-emerald-200"
      });
      fetchDashboard();
    } catch (error) {
      toast({
        variant: "destructive",
        title: "Erro",
        description: "N├úo foi poss├¡vel atualizar o status."
      });
    }
  };

  const getAlertColor = (vencimento: string | null) => {
    if (!vencimento) return "bg-slate-400";
    const days = differenceInDays(new Date(vencimento), new Date());
    if (days < 15) return "bg-red-600 shadow-red-200";
    if (days <= 30) return "bg-amber-500 shadow-amber-100";
    return "bg-emerald-500 shadow-emerald-100";
  };

  const safeData = data || {
    totalEscolas: 0,
    totalReceitas: 0,
    alertasEstoque: [],
    historicoMotor: [],
    alertasRemanejamento: [],
    escolasLista: []
  };

  const alertCount = safeData.alertasEstoque.length;
  const remanejamentoCount = safeData.alertasRemanejamento.length;

  return (
    <div className="p-8 max-w-7xl mx-auto space-y-10 animate-in fade-in duration-700">

      {/* Cabe├ºalho e Filtro */}
      <div className="flex flex-col gap-6">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
          <div>
            <h1 className="text-4xl font-black text-slate-900 tracking-tight">Dashboard Gerencial</h1>
            <p className="text-slate-500 mt-1 font-medium italic">Monitoramento em tempo real da rede municipal de alimenta├º├úo.</p>
          </div>

          <div className="flex items-center gap-3">
            <Dialog open={isModalOpen} onOpenChange={setIsModalOpen}>
              <DialogTrigger asChild>
                <Button className="bg-blue-600 hover:bg-blue-700 text-white font-bold shadow-lg shadow-blue-200 gap-2">
                  <Plus className="h-4 w-4" />
                  Novo Alerta de Validade
                </Button>
              </DialogTrigger>
              <DialogContent
                className="bg-white"
                onPointerDownOutside={(e) => e.preventDefault()}
                onEscapeKeyDown={(e) => e.preventDefault()}
              >
                <DialogHeader>
                  <DialogTitle>Registrar Alerta de Risco</DialogTitle>
                  <DialogDescription>Use este formul├írio para sinalizar itens pr├│ximos ao vencimento ou com excesso visual.</DialogDescription>
                </DialogHeader>
                <form onSubmit={handleCreateAlert} className="space-y-4 pt-4">
                  <div className="space-y-2">
                    <Label>Escola</Label>
                    <Select onValueChange={(val) => setNewAlert({ ...newAlert, escolaId: val })}>
                      <SelectTrigger>
                        <SelectValue placeholder="Selecione a unidade..." />
                      </SelectTrigger>
                      <SelectContent>
                        {escolas.map(e => <SelectItem key={e.id} value={e.id}>{e.name}</SelectItem>)}
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="space-y-2">
                    <Label>Item</Label>
                    <Select onValueChange={(val) => setNewAlert({ ...newAlert, itemId: val })}>
                      <SelectTrigger>
                        <SelectValue placeholder="Selecione o produto..." />
                      </SelectTrigger>
                      <SelectContent>
                        {items.map(i => <SelectItem key={i.id} value={i.id}>{i.name} ({i.baseUnit})</SelectItem>)}
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <Label>Quantidade em Risco</Label>
                      <Input type="number" step="0.01" required value={newAlert.quantidadeRisco} onChange={(e) => setNewAlert({ ...newAlert, quantidadeRisco: e.target.value })} />
                    </div>
                    <div className="space-y-2">
                      <Label>Vencimento Estimado</Label>
                      <Input type="date" value={newAlert.dataVencimento} onChange={(e) => setNewAlert({ ...newAlert, dataVencimento: e.target.value })} />
                    </div>
                  </div>
                  <DialogFooter className="pt-4">
                    <Button type="submit" disabled={isSubmitting} className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold">
                      {isSubmitting ? 'Salvando...' : 'Salvar Alerta'}
                    </Button>
                  </DialogFooter>
                </form>
              </DialogContent>
            </Dialog>

            <Badge variant="outline" className="px-4 py-1.5 border-slate-200 text-slate-500 font-bold bg-white">
              Atualizado: {format(new Date(), "HH:mm:ss")}
            </Badge>
          </div>
        </div>

        {/* Barra de Filtro por Unidade */}
        <div className="flex flex-col md:flex-row items-center gap-4 bg-white p-4 rounded-2xl shadow-sm border border-slate-100">
          <div className="flex items-center gap-2 text-slate-500 font-bold text-sm shrink-0">
            <Filter className="h-4 w-4" />
            Filtrar por Unidade:
          </div>
          <Select value={escolaFiltro} onValueChange={setEscolaFiltro}>
            <SelectTrigger className="max-w-md bg-slate-50 border-none font-medium text-slate-700">
              <SelectValue placeholder="Todas as Unidades" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">Todas as Escolas (Rede Global)</SelectItem>
              {escolas.map(e => (
                <SelectItem key={e.id} value={e.id}>{e.name}</SelectItem>
              ))}
            </SelectContent>
          </Select>
          {escolaFiltro !== "all" && (
            <Badge className="bg-blue-50 text-blue-600 border-blue-100 hover:bg-blue-100 transition-colors">
              Filtro Ativo: {escolas.find(e => e.id === escolaFiltro)?.name}
            </Badge>
          )}
        </div>
      </div>

      {loading ? (
        <div className="flex flex-col justify-center items-center py-20 gap-4">
          <div className="h-10 w-10 border-4 border-blue-600 border-t-transparent rounded-full animate-spin" />
          <p className="text-slate-500 font-bold animate-pulse">Atualizando indicadores da unidade...</p>
        </div>
      ) : (
        <>
          {/* Grade de Indicadores Principais (Interativa) */}
          <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-5 gap-6">

            {/* Unidades Atendidas */}
            <Card
