import React, { useState, useEffect } from 'react';
import { Card, CardHeader, CardTitle, CardDescription, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { useToast } from '@/hooks/use-toast';
import { api } from '../../services/api';

interface Escola {
  id: string;
  name: string;
}

interface ItemCatalogo {
  id: string;
  name: string;
}

export const Remanejamento: React.FC = () => {
  const [escolas, setEscolas] = useState<Escola[]>([]);
  const [itens, setItens] = useState<ItemCatalogo[]>([]);

  const [escolaOrigemId, setEscolaOrigemId] = useState('');
  const [escolaDestinoId, setEscolaDestinoId] = useState('');
  const [itemId, setItemId] = useState('');
  const [quantidade, setQuantidade] = useState<number | ''>('');

  const [isSubmitting, setIsSubmitting] = useState(false);
  const { toast } = useToast();

  useEffect(() => {
    const carregarDados = async () => {
      try {
        const [escolasResp, itensResp] = await Promise.all([
          api.get('/escolas'),
          api.get('/items')
        ]);
        setEscolas(escolasResp.data);
        setItens(itensResp.data);
      } catch (error) {
        console.error('Erro ao buscar dados:', error);
        toast({
          variant: "destructive",
          title: "Erro de Conex├úo",
          description: "N├úo foi poss├¡vel carregar a lista de escolas ou itens.",
        });
      }
    };
    carregarDados();
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    // Valida├º├úo de Preenchimento
    if (!escolaOrigemId || !escolaDestinoId || !itemId || !quantidade) {
      toast({
        variant: "destructive",
        title: "Aten├º├úo",
        description: "Preencha todos os campos obrigat├│rios.",
      });
      return;
    }

    // Regra R├¡gida: N├úo permita quantidades negativas ou zeradas.
    if (quantidade <= 0) {
      toast({
        variant: "destructive",
        title: "Aten├º├úo",
        description: "A quantidade a transferir deve ser estritamente maior que zero.",
      });
      return;
    }

    // Regra de UX Securit├íria
    if (escolaOrigemId === escolaDestinoId) {
      toast({
        variant: "destructive",
        title: "Aten├º├úo",
        description: "A escola de destino n├úo pode ser igual ├á de origem.",
      });
      return;
    }

    setIsSubmitting(true);
    try {
      await api.post('/estoque/remanejamento', {
        escolaOrigemId,
        escolaDestinoId,
        itemId,
        quantidade: Number(quantidade)
      });

      toast({
        title: "Sucesso",
        description: "Transfer├¬ncia realizada com sucesso.",
      });

      // Limpeza do Form
      setEscolaOrigemId('');
      setEscolaDestinoId('');
      setItemId('');
      setQuantidade('');
    } catch (error: any) {
      console.error(error);

      toast({
        variant: "destructive",
        title: "Erro na Transfer├¬ncia",
        description: "Estoque insuficiente na escola de origem para realizar esta transfer├¬ncia."
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  // Regra de UX: Filtrando o destino para n├úo incluir a origem selecionada
  const getEscolasDestinoValidas = () => {
    return escolas.filter(escola => escola.id !== escolaOrigemId);
  };

  return (
    <div className="p-8 max-w-4xl mx-auto flex flex-col gap-6">
      <div>
        <h1 className="text-3xl font-bold text-slate-800">Remanejamento Web</h1>
        <p className="text-slate-500 mt-1">Transfer├¬ncia log├¡stica de pacotes entre unidades escolares.</p>
      </div>

      <Card className="shadow-sm border-slate-200">
        <CardHeader>
          <CardTitle className="text-xl text-slate-700">Formul├írio de Transfer├¬ncia</CardTitle>
          <CardDescription>
            A movimenta├º├úo atualizar├í instantaneamente a grade de estoque do sistema de ambas as unidades.
          </CardDescription>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit} className="flex flex-col gap-6">

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="flex flex-col gap-2">
                <Label htmlFor="escolaOrigem" className="font-semibold text-slate-700">
                  Escola de Origem <span className="text-red-500">*</span>
                </Label>
                <Select value={escolaOrigemId} onValueChange={setEscolaOrigemId}>
                  <SelectTrigger id="escolaOrigem">
                    <SelectValue placeholder="Selecione a origem..." />
                  </SelectTrigger>
                  <SelectContent>
                    {escolas.map((esc) => (
                      <SelectItem key={esc.id} value={String(esc.id)}>{esc.name}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              <div className="flex flex-col gap-2">
                <Label htmlFor="escolaDestino" className="font-semibold text-slate-700">
                  Escola de Destino <span className="text-red-500">*</span>
                </Label>
                <Select
                  value={escolaDestinoId}
                  onValueChange={setEscolaDestinoId}
                  disabled={!escolaOrigemId}
                >
                  <SelectTrigger id="escolaDestino">
                    <SelectValue placeholder="Selecione o destino..." />
                  </SelectTrigger>
                  <SelectContent>
                    {getEscolasDestinoValidas().map((esc) => (
                      <SelectItem key={esc.id} value={String(esc.id)}>{esc.name}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="flex flex-col gap-2">
                <Label htmlFor="item" className="font-semibold text-slate-700">
                  Item Log├¡stico <span className="text-red-500">*</span>
                </Label>
                <Select value={itemId} onValueChange={setItemId}>
                  <SelectTrigger id="item">
                    <SelectValue placeholder="Selecione o item..." />
                  </SelectTrigger>
                  <SelectContent>
                    {itens.map((item) => (
                      <SelectItem key={item.id} value={String(item.id)}>{item.name}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              <div className="flex flex-col gap-2">
                <Label htmlFor="quantidade" className="font-semibold text-slate-700">
                  Quantidade a Transferir (Pacotes) <span className="text-red-500">*</span>
                </Label>
                <Input
                  id="quantidade"
                  type="number"
                  min="1"
                  step="1"
                  value={quantidade}
                  onChange={(e) => setQuantidade(e.target.value === '' ? '' : Number(e.target.value))}
                  placeholder="Ex: 5"
                />
              </div>
            </div>

            <div className="flex justify-end pt-4 border-t border-slate-100 mt-2">
              <Button type="submit" disabled={isSubmitting} className="w-full md:w-auto px-8">
                {isSubmitting ? 'Transferindo...' : 'Transferir Estoque'}
              </Button>
            </div>
          </form>
        </CardContent>
      </Card>
    </div>
  );
};

import React, { useState } from 'react';
import { createFicha } from '../../services/api/fichas';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { useNavigate } from 'react-router-dom';

export const FichaForm: React.FC = () => {
  const [name, setName] = useState('');
  const [type, setType] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim()) {
      setError('O nome da ficha ├® obrigat├│rio.');
      return;
    }

    setLoading(true);
    setError('');

    try {
      await createFicha({ name, type });
      navigate('/fichas');
    } catch (err: any) {
      console.error(err);
      setError('Erro ao criar a ficha t├®cnica.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="p-8 max-w-xl mx-auto flex flex-col gap-6">
      <div className="flex items-center justify-between">
        <h1 className="text-3xl font-bold text-slate-800">Nova Ficha T├®cnica</h1>
        <Button variant="outline" onClick={() => navigate('/fichas')}>Voltar</Button>
      </div>

      <form onSubmit={handleSave} className="flex flex-col gap-4 bg-white p-6 rounded-md shadow-sm border border-slate-200">
        <div className="flex flex-col gap-2">
          <Label htmlFor="name">Nome da Ficha</Label>
          <Input 
            id="name" 
            placeholder="Ex: Refei├º├úo B├ísica Padr├úo" 
            value={name} 
            onChange={(e) => setName(e.target.value)} 
          />
        </div>

        <div className="flex flex-col gap-2">
          <Label htmlFor="type">Tipo</Label>
          <Input 
            id="type" 
            placeholder="Ex: Almo├ºo / Lanche" 
            value={type} 
            onChange={(e) => setType(e.target.value)} 
          />
        </div>

        {error && <p className="text-sm font-medium text-red-600">{error}</p>}

        <Button type="submit" className="mt-4" disabled={loading}>
          {loading ? 'Salvando...' : 'Salvar'}
        </Button>
      </form>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { getFichas, createFicha, updateFicha, deleteFicha, type Ficha } from '../../services/api/fichas';
import { Card, CardHeader, CardTitle, CardDescription, CardContent } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter, DialogDescription } from '@/components/ui/dialog';
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from '@/components/ui/alert-dialog';
import { Pencil, Trash2, Plus, ClipboardList } from 'lucide-react';
import { useToast } from '@/hooks/use-toast';

export const FichasList: React.FC = () => {
  const [fichas, setFichas] = useState<Ficha[]>([]);
  const [loading, setLoading] = useState(false);

  // Cria├º├úo
  const [isCreateOpen, setIsCreateOpen] = useState(false);
  const [newName, setNewName] = useState('');
  const [newType, setNewType] = useState('');
  const [isSubmittingCreate, setIsSubmittingCreate] = useState(false);

  // Edi├º├úo
  const [fichaEmEdicao, setFichaEmEdicao] = useState<Ficha | null>(null);
  const [editName, setEditName] = useState('');
  const [editType, setEditType] = useState('');
  const [isSubmittingEdit, setIsSubmittingEdit] = useState(false);

  // Exclus├úo
  const [fichaParaExcluir, setFichaParaExcluir] = useState<Ficha | null>(null);
  const [isDeleting, setIsDeleting] = useState(false);

  const { toast } = useToast();

  const fetchFichas = async () => {
    setLoading(true);
    try {
      const data = await getFichas();
      setFichas(data);
    } catch (error) {
      console.error('Erro ao buscar fichas:', error);
      toast({ variant: "destructive", title: "Erro", description: "N├úo foi poss├¡vel carregar o cat├ílogo de receitas." });
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchFichas(); }, []);

  // --- Cria├º├úo ---
  const handleOpenCreate = () => {
    setNewName('');
    setNewType('');
    setIsCreateOpen(true);
  };

  const handleSubmitCreate = async () => {
    if (!newName.trim() || !newType.trim()) {
      toast({ variant: "destructive", title: "Aten├º├úo", description: "Nome e Tipo s├úo obrigat├│rios." });
      return;
    }
    setIsSubmittingCreate(true);
    try {
      await createFicha({ name: newName.trim(), type: newType.trim() });
      toast({ className: "bg-emerald-50 text-emerald-900 border-emerald-200", title: "Sucesso", description: "Receita criada com sucesso." });
      setIsCreateOpen(false);
      fetchFichas();
    } catch (error: any) {
      console.error('Erro ao criar ficha:', error);
      toast({ variant: "destructive", title: "Erro", description: error.response?.data?.error || "Erro ao criar a receita." });
    } finally {
      setIsSubmittingCreate(false);
    }
  };

  // --- Edi├º├úo ---
  const handleOpenEdit = (ficha: Ficha) => {
    setFichaEmEdicao(ficha);
    setEditName(ficha.name);
    setEditType(ficha.type || '');
  };

  const handleCloseEdit = () => setFichaEmEdicao(null);

  const handleSubmitEdit = async () => {
    if (!fichaEmEdicao) return;
    if (!editName.trim() || !editType.trim()) {
      toast({ variant: "destructive", title: "Aten├º├úo", description: "Nome e Tipo s├úo obrigat├│rios." });
      return;
    }
    setIsSubmittingEdit(true);
    try {
      await updateFicha(fichaEmEdicao.id, { name: editName.trim(), type: editType.trim() });
      toast({ className: "bg-emerald-50 text-emerald-900 border-emerald-200", title: "Sucesso", description: "Receita atualizada." });
      handleCloseEdit();
      fetchFichas();
    } catch (error: any) {
      console.error('Erro ao editar ficha:', error);
      toast({ variant: "destructive", title: "Erro", description: error.response?.data?.error || "Erro ao atualizar." });
    } finally {
      setIsSubmittingEdit(false);
    }
  };

  // --- Exclus├úo ---
  const handleConfirmDelete = async () => {
    if (!fichaParaExcluir) return;
    setIsDeleting(true);
    try {
      await deleteFicha(fichaParaExcluir.id);
      toast({ className: "bg-emerald-50 text-emerald-900 border-emerald-200", title: "Sucesso", description: "Receita exclu├¡da." });
      fetchFichas();
    } catch (error: any) {
      console.error('Erro ao excluir ficha:', error);
      if (error.response?.status === 400) {
        toast({ variant: "destructive", title: "Exclus├úo Bloqueada", description: error.response?.data?.error || "Esta ficha est├í vinculada a um card├ípio ou preparo." });
      } else {
        toast({ variant: "destructive", title: "Erro", description: "Erro interno ao excluir ficha." });
      }
    } finally {
      setIsDeleting(false);
      setFichaParaExcluir(null);
    }
  };

  return (
    <div className="p-8 max-w-6xl mx-auto flex flex-col gap-6">
      <div className="flex justify-between items-start">
        <div>
          <h1 className="text-3xl font-bold text-foreground flex items-center gap-3">
            <ClipboardList className="h-8 w-8 text-blue-600" />
            Cat├ílogo de Receitas
          </h1>
          <p className="text-muted-foreground mt-1">Cat├ílogo de receitas. Os ingredientes s├úo configurados por escola.</p>
        </div>
        <Button onClick={handleOpenCreate} className="bg-blue-600 hover:bg-blue-700 text-white">
          <Plus className="mr-2 h-4 w-4" /> Nova Receita
        </Button>
      </div>

      <Card className="shadow-sm border-slate-200">
        <CardHeader>
          <CardTitle className="text-xl text-slate-700">Receitas Cadastradas</CardTitle>
          <CardDescription>Cada item define uma receita. As quantidades s├úo configuradas por unidade escolar.</CardDescription>
        </CardHeader>
        <CardContent>
          {loading ? (
            <div className="py-8 text-center text-slate-500">Carregando fichas...</div>
          ) : (
            <Table>
              <TableHeader className="bg-slate-50">
                <TableRow>
                  <TableHead className="font-semibold text-slate-700 px-6 py-4">Nome da Receita</TableHead>
                  <TableHead className="font-semibold text-slate-700 px-6 py-4">Tipo</TableHead>
                  <TableHead className="font-semibold text-slate-700 px-6 py-4">Data de Cria├º├úo</TableHead>
                  <TableHead className="text-right font-semibold text-slate-700 px-6 py-4">A├º├Áes</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {fichas.length === 0 ? (
                  <TableRow>
                    <TableCell colSpan={4} className="text-center py-8 text-slate-500">
                      Nenhuma receita encontrada.
                    </TableCell>
                  </TableRow>
                ) : (
                  fichas.map((ficha) => (
                    <TableRow key={ficha.id} className="hover:bg-slate-50 transition-colors">
                      <TableCell className="font-medium text-slate-800 px-6 py-4">{ficha.name}</TableCell>
                      <TableCell className="text-slate-600 px-6 py-4">{ficha.type || 'ÔÇö'}</TableCell>
                      <TableCell className="text-slate-600 px-6 py-4">
                        {ficha.createdAt ? new Date(ficha.createdAt).toLocaleDateString('pt-BR') : 'ÔÇö'}
                      </TableCell>
                      <TableCell className="text-right px-6 py-4">
                        <div className="flex justify-end gap-2">
                          <Button variant="outline" size="sm" className="h-8 w-8 p-0 text-slate-500 hover:text-blue-600 hover:bg-blue-50 border-slate-200" onClick={() => handleOpenEdit(ficha)}>
                            <Pencil className="h-4 w-4" />
                          </Button>
                          <Button variant="outline" size="sm" className="h-8 w-8 p-0 text-slate-500 hover:text-red-600 hover:bg-red-50 border-slate-200" onClick={() => setFichaParaExcluir(ficha)}>
                            <Trash2 className="h-4 w-4" />
                          </Button>
                        </div>
                      </TableCell>
                    </TableRow>
                  ))
                )}
              </TableBody>
            </Table>
          )}
        </CardContent>
      </Card>

      {/* ========== Modal de Cria├º├úo ========== */}
      <Dialog open={isCreateOpen} onOpenChange={(open) => !open && setIsCreateOpen(false)}>
        <DialogContent 
          className="sm:max-w-[450px] bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800 opacity-100"
          onPointerDownOutside={(e) => e.preventDefault()}
          onEscapeKeyDown={(e) => e.preventDefault()}
        >
          <DialogHeader>
            <DialogTitle className="text-slate-900 dark:text-slate-100">Nova Receita</DialogTitle>
            <DialogDescription className="text-slate-500 dark:text-slate-400">
              Cadastre a receita. Os ingredientes ser├úo configurados por escola.
            </DialogDescription>
          </DialogHeader>
          <div className="flex flex-col gap-4 py-4">
            <div className="flex flex-col gap-2">
              <Label className="text-slate-900 dark:text-slate-200 font-semibold">Nome da Receita</Label>
              <Input value={newName} onChange={(e) => setNewName(e.target.value)} placeholder="Ex: Bolo de Cenoura" />
            </div>
            <div className="flex flex-col gap-2">
              <Label className="text-slate-900 dark:text-slate-200 font-semibold">Tipo</Label>
              <Input value={newType} onChange={(e) => setNewType(e.target.value)} placeholder="Ex: Sobremesa, Caf├® da Manh├ú" />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setIsCreateOpen(false)} disabled={isSubmittingCreate}>Cancelar</Button>
            <Button onClick={handleSubmitCreate} disabled={isSubmittingCreate} className="bg-blue-600 hover:bg-blue-700 text-white">
              {isSubmittingCreate ? 'Criando...' : 'Criar Receita'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* ========== Modal de Edi├º├úo ========== */}
      <Dialog open={!!fichaEmEdicao} onOpenChange={(open) => !open && handleCloseEdit()}>
        <DialogContent className="sm:max-w-[450px] bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800 opacity-100">
          <DialogHeader>
            <DialogTitle className="text-slate-900 dark:text-slate-100">Editar Receita</DialogTitle>
            <DialogDescription className="text-slate-500 dark:text-slate-400">Ajuste os dados da receita.</DialogDescription>
          </DialogHeader>
          <div className="flex flex-col gap-4 py-4">
            <div className="flex flex-col gap-2">
              <Label className="text-slate-900 dark:text-slate-200 font-semibold">Nome da Receita</Label>
              <Input value={editName} onChange={(e) => setEditName(e.target.value)} placeholder="Ex: Bolo de Cenoura" />
            </div>
            <div className="flex flex-col gap-2">
              <Label className="text-slate-900 dark:text-slate-200 font-semibold">Tipo</Label>
              <Input value={editType} onChange={(e) => setEditType(e.target.value)} placeholder="Ex: Sobremesa, Caf├® da Manh├ú" />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={handleCloseEdit} disabled={isSubmittingEdit}>Cancelar</Button>
            <Button onClick={handleSubmitEdit} disabled={isSubmittingEdit} className="bg-blue-600 hover:bg-blue-700 text-white">
              {isSubmittingEdit ? 'Salvando...' : 'Salvar Altera├º├Áes'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* ========== Modal de Exclus├úo ========== */}
      <AlertDialog open={!!fichaParaExcluir} onOpenChange={(open) => !open && setFichaParaExcluir(null)}>
        <AlertDialogContent className="bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800 opacity-100">
          <AlertDialogHeader>
            <AlertDialogTitle className="text-slate-900 dark:text-slate-100">
              Excluir "{fichaParaExcluir?.name}"?
            </AlertDialogTitle>
            <AlertDialogDescription className="text-slate-500 dark:text-slate-400">
              Se vinculada a um card├ípio ou preparo de escola, a exclus├úo ser├í bloqueada.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel disabled={isDeleting} className="text-slate-900 dark:text-slate-100 border-slate-200 dark:border-slate-800">Cancelar</AlertDialogCancel>
            <AlertDialogAction onClick={(e) => { e.preventDefault(); handleConfirmDelete(); }} disabled={isDeleting} className="bg-red-600 hover:bg-red-700 text-white">
              {isDeleting ? 'Excluindo...' : 'Sim, Excluir Receita'}
