import React, { useState } from 'react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Card, CardHeader, CardTitle, CardDescription, CardContent, CardFooter } from '@/components/ui/card';
import { Table, TableHeader, TableRow, TableHead, TableBody, TableCell } from '@/components/ui/table';
import { useToast } from '@/hooks/use-toast';
import { api } from '../../services/api';

interface BaixaLote {
  tipo: string;
  escolaId: string;
  itemId: string;
  pacotesFisicosAbatidos: number;
  saldoFinal: number;
}

export const ProcessamentoLote: React.FC = () => {
  const [dataConsumo, setDataConsumo] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [logResultados, setLogResultados] = useState<BaixaLote[]>([]);
  const { toast } = useToast();

  const handleProcessar = async () => {
    if (!dataConsumo) {
      toast({
        variant: "destructive",
        title: "Aviso",
        description: "Selecione uma data para o processamento.",
      });
      return;
    }

    setIsProcessing(true);
    setLogResultados([]);

    try {
      const response = await api.post('/consumos/processar-lote', {
        data_consumo: dataConsumo
      });

      const baixas = response.data.baixas_lote || [];
      setLogResultados(baixas);

      toast({
        title: "Sucesso!",
        description: response.data.message || "Processamento conclu├¡do com sucesso.",
      });

    } catch (error: any) {
      console.error("Erro no processamento em lote:", error);

      if (error.response?.data?.error) {
        const errorData = error.response.data.error;
        if (errorData.code === 'ESTOQUE_NEGATIVO') {
          toast({
             variant: "destructive",
             title: "Erro Cr├¡tico de Estoque",
             description: `Estoque insuficiente na escola ${errorData.escolaNome || errorData.escolaId} para o item ${errorData.itemNome || errorData.itemId}. Faltam ${errorData.quantidadeFaltante} pacotes.`
          });
          return;
        }
      }

      toast({
        variant: "destructive",
        title: "Erro no Servidor",
        description: "Ocorreu um erro ao processar o lote de consumo.",
      });
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="p-8 max-w-5xl mx-auto flex flex-col gap-6">
      <Card className="shadow-sm border-slate-200">
        <CardHeader>
          <CardTitle className="text-3xl font-bold text-slate-800">Processamento em Lote (Super-Motor)</CardTitle>
          <CardDescription className="text-slate-500 mt-2">
            Defina a data para abater o planejamento e os consumos fixos do estoque de todas as escolas simultaneamente.
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="flex flex-col gap-2 max-w-sm mt-4">
            <Label htmlFor="data_consumo" className="font-semibold text-slate-700">Data de Consumo <span className="text-red-500">*</span></Label>
            <Input 
              id="data_consumo" 
              type="date" 
              value={dataConsumo} 
              onChange={(e) => setDataConsumo(e.target.value)} 
              className="mt-1"
            />
          </div>
        </CardContent>
        <CardFooter className="flex justify-end border-t border-slate-100 pt-6 mt-2">
          <Button 
            onClick={handleProcessar} 
            disabled={isProcessing || !dataConsumo} 
            className="px-8 py-6 text-md font-semibold"
          >
            {isProcessing ? 'Processando...' : 'Processar Consumo do Dia'}
          </Button>
        </CardFooter>
      </Card>

      {logResultados.length > 0 && (
        <Card className="shadow-sm border-slate-200 animate-in fade-in slide-in-from-top-2 duration-300">
          <CardHeader>
            <CardTitle className="text-xl text-slate-800">Log de Baixas (Recibo)</CardTitle>
          </CardHeader>
          <CardContent className="p-0">
            <Table>
              <TableHeader className="bg-slate-50">
                <TableRow>
                  <TableHead className="px-6 py-4 font-semibold text-slate-700">Tipo de Baixa</TableHead>
                  <TableHead className="px-6 py-4 font-semibold text-slate-700">ID da Escola</TableHead>
                  <TableHead className="px-6 py-4 font-semibold text-slate-700">ID do Item</TableHead>
                  <TableHead className="px-6 py-4 font-semibold text-slate-700 text-right">Qtd. Abatida (Pacotes)</TableHead>
                  <TableHead className="px-6 py-4 font-semibold text-slate-700 text-right">Saldo Final</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {logResultados.map((log, index) => (
                  <TableRow key={index} className="hover:bg-slate-50/50 transition-colors">
                    <TableCell className="px-6 py-3 font-medium">{log.tipo}</TableCell>
                    <TableCell className="px-6 py-3">{log.escolaId}</TableCell>
                    <TableCell className="px-6 py-3">{log.itemId}</TableCell>
                    <TableCell className="px-6 py-3 text-right text-rose-600 font-semibold">
                      -{log.pacotesFisicosAbatidos}
                    </TableCell>
                    <TableCell className="px-6 py-3 text-right font-semibold text-slate-700">
                      {log.saldoFinal}
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </CardContent>
        </Card>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Card, CardHeader, CardTitle, CardDescription, CardContent } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter, DialogDescription } from '@/components/ui/dialog';
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from '@/components/ui/alert-dialog';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Pencil, Trash2, Plus, School, UtensilsCrossed } from 'lucide-react';
import { useToast } from '@/hooks/use-toast';
import { api } from '../../services/api';
import { PreparosPanel } from './PreparosPanel';

const getHeaders = () => {
  const token = localStorage.getItem('token');
  return { headers: { Authorization: `Bearer ${token}` } };
};

interface Rota {
  id: string;
  name: string;
}

interface Escola {
  id: string;
  name: string;
  type: string;
  rotaId: string;
  endereco?: string;
  latitude?: number;
  longitude?: number;
  rota?: Rota;
}

const TIPOS_UNIDADE = [
  { value: 'CRECHE', label: 'Creche' },
  { value: 'FUNDAMENTAL', label: 'Fundamental' },
  { value: 'INTEGRAL', label: 'Integral' },
  { value: 'PARCIAL', label: 'Parcial' },
  { value: 'EJA', label: 'EJA' },
];

export const Escolas: React.FC = () => {
  const [escolas, setEscolas] = useState<Escola[]>([]);
  const [rotas, setRotas] = useState<Rota[]>([]);
  const [loading, setLoading] = useState(false);

  const [isCreateOpen, setIsCreateOpen] = useState(false);
  const [newName, setNewName] = useState('');
  const [newType, setNewType] = useState('');
  const [newEndereco, setNewEndereco] = useState('');
  const [newLatitude, setNewLatitude] = useState('');
  const [newLongitude, setNewLongitude] = useState('');
  const [newRotaId, setNewRotaId] = useState('');
  const [isSubmittingCreate, setIsSubmittingCreate] = useState(false);

  const [escolaEmEdicao, setEscolaEmEdicao] = useState<Escola | null>(null);
  const [editName, setEditName] = useState('');
  const [editType, setEditType] = useState('');
  const [editEndereco, setEditEndereco] = useState('');
  const [editLatitude, setEditLatitude] = useState('');
  const [editLongitude, setEditLongitude] = useState('');
  const [editRotaId, setEditRotaId] = useState('');
  const [isSubmittingEdit, setIsSubmittingEdit] = useState(false);

  const [escolaParaExcluir, setEscolaParaExcluir] = useState<Escola | null>(null);
  const [isDeleting, setIsDeleting] = useState(false);

  // Preparos
  const [escolaPreparos, setEscolaPreparos] = useState<Escola | null>(null);

  const { toast } = useToast();

  const [user, setUser] = useState<any>(() => {
    const raw = localStorage.getItem('usuario');
    return raw ? JSON.parse(raw) : null;
  });

  const fetchProfile = async () => {
    if (!user) {
      try {
        const response = await api.get('/auth/me', getHeaders());
        localStorage.setItem('usuario', JSON.stringify(response.data));
        setUser(response.data);
      } catch (error) {
        console.error('Erro ao buscar perfil:', error);
      }
    }
  };

  useEffect(() => { 
    fetchEscolas(); 
    fetchRotas(); 
    fetchProfile();
  }, []);

  const isAdmin = user?.role === 'ADMIN';
  const isNutri = user?.role === 'NUTRICIONISTA';
  const canCreate = isAdmin || isNutri;

  const fetchEscolas = async () => {
    setLoading(true);
    try {
      const response = await api.get('/escolas', getHeaders());
      setEscolas(response.data);
    } catch (error: any) {
      console.error('Erro ao buscar escolas:', error);
      toast({ variant: "destructive", title: "Erro", description: "N├úo foi poss├¡vel carregar as escolas." });
    } finally {
      setLoading(false);
    }
  };

  const fetchRotas = async () => {
    try {
      const response = await api.get('/rotas', getHeaders());
      setRotas(response.data);
    } catch (error: any) {
      console.error('Erro ao buscar rotas:', error);
    }
  };

  const getRotaName = (rotaId: string) => {
    const rota = rotas.find(r => r.id === rotaId);
    return rota?.name || 'ÔÇö';
  };

  // --- Cria├º├úo ---
  const handleOpenCreate = () => {
    setNewName(''); setNewType(''); setNewEndereco(''); setNewLatitude(''); setNewLongitude(''); setNewRotaId('');
    setIsCreateOpen(true);
  };

  const canSaveCreate = newName.trim() && newType && newRotaId;

  const handleSubmitCreate = async () => {
    if (!newName.trim() || !newType || !newRotaId) {
      toast({ variant: "destructive", title: "Aten├º├úo", description: "Todos os campos s├úo obrigat├│rios. Selecione uma Rota." });
      return;
    }
    setIsSubmittingCreate(true);
    try {
      await api.post('/escolas', { 
        name: newName.trim(), 
        type: newType, 
        endereco: newEndereco.trim(),
        latitude: newLatitude ? parseFloat(newLatitude) : null,
        longitude: newLongitude ? parseFloat(newLongitude) : null,
        rota_id: newRotaId 
      }, getHeaders());
      toast({ className: "bg-emerald-50 text-emerald-900 border-emerald-200", title: "Sucesso", description: "Escola criada com sucesso." });
      setIsCreateOpen(false);
      fetchEscolas();
    } catch (error: any) {
      console.error('Erro ao criar escola:', error);
      toast({ variant: "destructive", title: "Erro", description: error.response?.data?.error || "Erro ao criar escola." });
    } finally {
      setIsSubmittingCreate(false);
    }
  };

  // --- Edi├º├úo ---
  const handleOpenEdit = (escola: Escola) => {
    setEscolaEmEdicao(escola);
    setEditName(escola.name);
    setEditType(escola.type);
    setEditEndereco(escola.endereco || '');
    setEditLatitude(escola.latitude?.toString() || '');
    setEditLongitude(escola.longitude?.toString() || '');
    setEditRotaId(escola.rotaId);
  };

  const canSaveEdit = editName.trim() && editType && editRotaId;

  const handleSubmitEdit = async () => {
    if (!escolaEmEdicao || !editName.trim() || !editType || !editRotaId) {
      toast({ variant: "destructive", title: "Aten├º├úo", description: "Todos os campos s├úo obrigat├│rios. Selecione uma Rota." });
      return;
    }
    setIsSubmittingEdit(true);
    try {
      await api.put(`/escolas/${escolaEmEdicao.id}`, { 
        name: editName.trim(), 
        type: editType, 
        endereco: editEndereco.trim(),
        latitude: editLatitude ? parseFloat(editLatitude) : null,
        longitude: editLongitude ? parseFloat(editLongitude) : null,
        rota_id: editRotaId 
      }, getHeaders());
      toast({ className: "bg-emerald-50 text-emerald-900 border-emerald-200", title: "Sucesso", description: "Escola atualizada." });
      setEscolaEmEdicao(null);
      fetchEscolas();
    } catch (error: any) {
      console.error('Erro ao editar escola:', error);
      toast({ variant: "destructive", title: "Erro", description: error.response?.data?.error || "Erro ao atualizar." });
    } finally {
      setIsSubmittingEdit(false);
    }
  };

  // --- Exclus├úo ---
  const handleConfirmDelete = async () => {
    if (!escolaParaExcluir) return;
    setIsDeleting(true);
    try {
      await api.delete(`/escolas/${escolaParaExcluir.id}`, getHeaders());
      toast({ className: "bg-emerald-50 text-emerald-900 border-emerald-200", title: "Sucesso", description: "Escola exclu├¡da." });
      fetchEscolas();
    } catch (error: any) {
      if (error.response?.status === 400) {
        toast({ variant: "destructive", title: "Exclus├úo Bloqueada", description: error.response?.data?.error || "Escola possui hist├│rico de estoque ou metas vinculados." });
      } else {
        toast({ variant: "destructive", title: "Erro", description: "Erro ao excluir escola." });
      }
    } finally {
      setIsDeleting(false);
      setEscolaParaExcluir(null);
    }
  };

  const getTipoBadgeColor = (type: string) => {
    const colors: Record<string, string> = {
      CRECHE: 'bg-pink-50 text-pink-700',
      FUNDAMENTAL: 'bg-indigo-50 text-indigo-700',
      INTEGRAL: 'bg-amber-50 text-amber-700',
      PARCIAL: 'bg-cyan-50 text-cyan-700',
      EJA: 'bg-violet-50 text-violet-700',
    };
    return colors[type] || 'bg-slate-100 text-slate-700';
  };

    return (
    <div className="p-8 max-w-6xl mx-auto flex flex-col gap-6">
      <div className="flex justify-between items-start">
        <div>
          <h1 className="text-3xl font-bold text-foreground flex items-center gap-3">
            <School className="h-8 w-8 text-blue-600" />
            Escolas
          </h1>
          <p className="text-muted-foreground mt-1">Gerencie as unidades escolares da rede.</p>
        </div>
        {canCreate && (
          <Button onClick={handleOpenCreate} className="bg-blue-600 hover:bg-blue-700 text-white">
            <Plus className="mr-2 h-4 w-4" /> Nova Escola
          </Button>
        )}
      </div>

      <Card className="shadow-sm border-slate-200">
        <CardHeader>
          <CardTitle className="text-xl text-slate-700">Escolas Cadastradas</CardTitle>
          <CardDescription>Unidades escolares vinculadas ├ás rotas de entrega.</CardDescription>
        </CardHeader>
        <CardContent>
          {loading ? (
            <div className="py-8 text-center text-slate-500">Carregando escolas...</div>
          ) : (
            <Table>
              <TableHeader className="bg-slate-50">
                <TableRow>
                  <TableHead className="font-semibold text-slate-700 px-6 py-4">Nome da Escola</TableHead>
                  <TableHead className="font-semibold text-slate-700 px-6 py-4">Tipo</TableHead>
                  <TableHead className="font-semibold text-slate-700 px-6 py-4">Rota</TableHead>
                  <TableHead className="text-right font-semibold text-slate-700 px-6 py-4">A├º├Áes</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {escolas.length === 0 ? (
                  <TableRow>
                    <TableCell colSpan={4} className="text-center py-8 text-slate-500">Nenhuma escola cadastrada.</TableCell>
                  </TableRow>
                ) : escolas.map((escola) => (
                  <TableRow key={escola.id} className="hover:bg-slate-50 transition-colors">
                    <TableCell className="font-medium text-slate-800 px-6 py-4">{escola.name}</TableCell>
                    <TableCell className="px-6 py-4">
                      <span className={`inline-flex items-center rounded-full px-2.5 py-0.5 text-xs font-medium ${getTipoBadgeColor(escola.type)}`}>
                        {escola.type}
                      </span>
                    </TableCell>
                    <TableCell className="text-slate-600 px-6 py-4">{getRotaName(escola.rotaId)}</TableCell>
                    <TableCell className="text-right px-6 py-4">
                      <div className="flex justify-end gap-2">
                        <Button variant="outline" size="sm" className="h-8 px-2 text-xs text-amber-700 hover:text-amber-800 hover:bg-amber-50 border-amber-200" onClick={() => setEscolaPreparos(escola)} title="Configurar Preparos">
                          <UtensilsCrossed className="h-3.5 w-3.5 mr-1" /> Preparos
                        </Button>
                        <Button variant="outline" size="sm" className="h-8 w-8 p-0 text-slate-500 hover:text-blue-600 hover:bg-blue-50 border-slate-200" onClick={() => handleOpenEdit(escola)}>
                          <Pencil className="h-4 w-4" />
                        </Button>
                        {(isAdmin || isNutri) && (
                          <Button variant="outline" size="sm" className="h-8 w-8 p-0 text-slate-500 hover:text-red-600 hover:bg-red-50 border-slate-200" onClick={() => setEscolaParaExcluir(escola)}>
                            <Trash2 className="h-4 w-4" />
                          </Button>
                        )}
                      </div>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          )}
        </CardContent>
      </Card>

      {/* Modal de Cria├º├úo */}
      <Dialog open={isCreateOpen} onOpenChange={(open) => !open && setIsCreateOpen(false)}>
        <DialogContent 
          className="sm:max-w-[480px] bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800 opacity-100"
          onPointerDownOutside={(e) => e.preventDefault()}
          onEscapeKeyDown={(e) => e.preventDefault()}
        >
          <DialogHeader>
            <DialogTitle className="text-slate-900 dark:text-slate-100">Nova Escola</DialogTitle>
            <DialogDescription className="text-slate-500 dark:text-slate-400">Preencha os dados da unidade escolar.</DialogDescription>
          </DialogHeader>
          <div className="flex flex-col gap-4 py-4">
            <div className="flex flex-col gap-2">
              <Label className="text-slate-900 dark:text-slate-200 font-semibold">Nome da Escola</Label>
              <Input placeholder="Ex: EMEI Monteiro Lobato" value={newName} onChange={(e) => setNewName(e.target.value)} />
            </div>
            <div className="flex flex-col gap-2">
              <Label className="text-slate-900 dark:text-slate-200 font-semibold">Tipo de Unidade</Label>
              <Select value={newType} onValueChange={setNewType}>
                <SelectTrigger className="bg-white dark:bg-slate-950 text-slate-900 dark:text-slate-100">
                  <SelectValue placeholder="Selecione o tipo" />
                </SelectTrigger>
                <SelectContent className="bg-white dark:bg-slate-950 border-slate-200 dark:border-slate-800">
                  {TIPOS_UNIDADE.map((t) => (
                    <SelectItem key={t.value} value={t.value} className="text-slate-900 dark:text-slate-100 focus:bg-slate-100 dark:focus:bg-slate-800">{t.label}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div className="flex flex-col gap-2">
              <Label className="text-slate-900 dark:text-slate-200 font-semibold">Rota de Entrega</Label>
              <Select value={newRotaId} onValueChange={setNewRotaId}>
                <SelectTrigger className="bg-white dark:bg-slate-950 text-slate-900 dark:text-slate-100">
                  <SelectValue placeholder="Selecione a rota" />
                </SelectTrigger>
                <SelectContent className="bg-white dark:bg-slate-950 border-slate-200 dark:border-slate-800">
                  {rotas.map((r) => (
                    <SelectItem key={r.id} value={r.id} className="text-slate-900 dark:text-slate-100 focus:bg-slate-100 dark:focus:bg-slate-800">{r.name}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
              {rotas.length === 0 && (
                <p className="text-xs text-amber-600">Nenhuma rota cadastrada. Cadastre uma rota primeiro.</p>
              )}
            </div>
            <div className="flex flex-col gap-2">
              <Label className="text-slate-900 dark:text-slate-200 font-semibold">Endere├ºo Completo</Label>
              <Input placeholder="Rua, N├║mero, Bairro..." value={newEndereco} onChange={(e) => setNewEndereco(e.target.value)} />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="flex flex-col gap-2">
                <Label className="text-slate-900 dark:text-slate-200 font-semibold">Latitude</Label>
                <Input type="number" step="any" placeholder="-23.5505" value={newLatitude} onChange={(e) => setNewLatitude(e.target.value)} />
              </div>
              <div className="flex flex-col gap-2">
                <Label className="text-slate-900 dark:text-slate-200 font-semibold">Longitude</Label>
                <Input type="number" step="any" placeholder="-46.6333" value={newLongitude} onChange={(e) => setNewLongitude(e.target.value)} />
              </div>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setIsCreateOpen(false)} disabled={isSubmittingCreate}>Cancelar</Button>
            <Button onClick={handleSubmitCreate} disabled={isSubmittingCreate || !canSaveCreate} className="bg-blue-600 hover:bg-blue-700 text-white">
              {isSubmittingCreate ? 'Criando...' : 'Criar Escola'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Modal de Edi├º├úo */}
      <Dialog open={!!escolaEmEdicao} onOpenChange={(open) => !open && setEscolaEmEdicao(null)}>
        <DialogContent 
          className="sm:max-w-[480px] bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800 opacity-100"
          onPointerDownOutside={(e) => e.preventDefault()}
          onEscapeKeyDown={(e) => e.preventDefault()}
        >
          <DialogHeader>
            <DialogTitle className="text-slate-900 dark:text-slate-100">Editar Escola</DialogTitle>
            <DialogDescription className="text-slate-500 dark:text-slate-400">Ajuste os dados da unidade escolar.</DialogDescription>
          </DialogHeader>
          <div className="flex flex-col gap-4 py-4">
            <div className="flex flex-col gap-2">
              <Label className="text-slate-900 dark:text-slate-200 font-semibold">Nome da Escola</Label>
              <Input value={editName} onChange={(e) => setEditName(e.target.value)} />
            </div>
            <div className="flex flex-col gap-2">
              <Label className="text-slate-900 dark:text-slate-200 font-semibold">Tipo de Unidade</Label>
              <Select value={editType} onValueChange={setEditType}>
                <SelectTrigger className="bg-white dark:bg-slate-950 text-slate-900 dark:text-slate-100">
                  <SelectValue placeholder="Selecione o tipo" />
                </SelectTrigger>
                <SelectContent className="bg-white dark:bg-slate-950 border-slate-200 dark:border-slate-800">
                  {TIPOS_UNIDADE.map((t) => (
                    <SelectItem key={t.value} value={t.value} className="text-slate-900 dark:text-slate-100 focus:bg-slate-100 dark:focus:bg-slate-800">{t.label}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div className="flex flex-col gap-2">
              <Label className="text-slate-900 dark:text-slate-200 font-semibold">Rota de Entrega</Label>
              <Select value={editRotaId} onValueChange={setEditRotaId}>
                <SelectTrigger className="bg-white dark:bg-slate-950 text-slate-900 dark:text-slate-100">
                  <SelectValue placeholder="Selecione a rota" />
                </SelectTrigger>
                <SelectContent className="bg-white dark:bg-slate-950 border-slate-200 dark:border-slate-800">
                  {rotas.map((r) => (
                    <SelectItem key={r.id} value={r.id} className="text-slate-900 dark:text-slate-100 focus:bg-slate-100 dark:focus:bg-slate-800">{r.name}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div className="flex flex-col gap-2">
              <Label className="text-slate-900 dark:text-slate-200 font-semibold">Endere├ºo Completo</Label>
              <Input value={editEndereco} onChange={(e) => setEditEndereco(e.target.value)} />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="flex flex-col gap-2">
                <Label className="text-slate-900 dark:text-slate-200 font-semibold">Latitude</Label>
                <Input type="number" step="any" value={editLatitude} onChange={(e) => setEditLatitude(e.target.value)} />
              </div>
              <div className="flex flex-col gap-2">
                <Label className="text-slate-900 dark:text-slate-200 font-semibold">Longitude</Label>
                <Input type="number" step="any" value={editLongitude} onChange={(e) => setEditLongitude(e.target.value)} />
              </div>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setEscolaEmEdicao(null)} disabled={isSubmittingEdit}>Cancelar</Button>
            <Button onClick={handleSubmitEdit} disabled={isSubmittingEdit || !canSaveEdit} className="bg-blue-600 hover:bg-blue-700 text-white">
              {isSubmittingEdit ? 'Salvando...' : 'Salvar Altera├º├Áes'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Modal de Exclus├úo */}
      <AlertDialog open={!!escolaParaExcluir} onOpenChange={(open) => !open && setEscolaParaExcluir(null)}>
        <AlertDialogContent className="bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800 opacity-100">
          <AlertDialogHeader>
            <AlertDialogTitle className="text-slate-900 dark:text-slate-100">Excluir "{escolaParaExcluir?.name}"?</AlertDialogTitle>
            <AlertDialogDescription className="text-slate-500 dark:text-slate-400">
              Se a escola possuir hist├│rico de estoque ou metas, a exclus├úo ser├í bloqueada.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel disabled={isDeleting} className="text-slate-900 dark:text-slate-100 border-slate-200 dark:border-slate-800">Cancelar</AlertDialogCancel>
            <AlertDialogAction onClick={(e) => { e.preventDefault(); handleConfirmDelete(); }} disabled={isDeleting} className="bg-red-600 hover:bg-red-700 text-white">
              {isDeleting ? 'Excluindo...' : 'Sim, Excluir Escola'}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      {/* Panel de Preparos */}
      <PreparosPanel
        escolaId={escolaPreparos?.id || ''}
        escolaNome={escolaPreparos?.name || ''}
        open={!!escolaPreparos}
        onClose={() => setEscolaPreparos(null)}
      />
    </div>
  );
};

import React, { useEffect, useState, useMemo } from 'react';
import { Card, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Tabs, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter, DialogDescription } from '@/components/ui/dialog';
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from '@/components/ui/alert-dialog';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Plus, X, Search, Pencil, Copy, LinkIcon, AlertTriangle, UtensilsCrossed, ChefHat, Package } from 'lucide-react';
import { useToast } from '@/hooks/use-toast';
import { api } from '../../services/api';
import { getFichas, type Ficha } from '../../services/api/fichas';

const getHeaders = () => {
  const token = localStorage.getItem('token');
  return { headers: { Authorization: `Bearer ${token}` } };
};

interface PreparoIngrediente {
  id: string;
  itemId: string;
  quantidade: number;
  item: { id: string; name: string; baseUnit: string; packagingSize: number };
}

interface Preparo {
  id: string;
  escolaId: string;
  fichaTecnicaId: string;
  fichaTecnica: { id: string; name: string; type: string };
  ingredientes: PreparoIngrediente[];
}

interface CatalogoItem {
  id: string;
  name: string;
  baseUnit: string;
}

interface IngForm {
  itemId: string;
  quantidade: number | '';
}

interface Props {
  escolaId: string;
  escolaNome: string;
  open: boolean;
  onClose: () => void;
}

const TIPO_REFEICAO_COLORS: Record<string, { bg: string; text: string; border: string }> = {
  DESJEJUM: { bg: 'bg-orange-50', text: 'text-orange-700', border: 'border-orange-200' },
  MERENDA: { bg: 'bg-emerald-50', text: 'text-emerald-700', border: 'border-emerald-200' },
};

const getTypeBadgeStyle = (type: string) => {
  const upper = type?.toUpperCase();
  return TIPO_REFEICAO_COLORS[upper] || { bg: 'bg-slate-50', text: 'text-slate-600', border: 'border-slate-200' };
};

export const PreparosPanel: React.FC<Props> = ({ escolaId, escolaNome, open, onClose }) => {
  const [preparos, setPreparos] = useState<Preparo[]>([]);
  const [fichas, setFichas] = useState<Ficha[]>([]);
  const [catalogoItems, setCatalogoItems] = useState<CatalogoItem[]>([]);
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [filtroTipo, setFiltroTipo] = useState('TODOS');

  // Formul├írio de add/edit preparo
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingPreparo, setEditingPreparo] = useState<Preparo | null>(null);
  const [selectedFichaId, setSelectedFichaId] = useState('');
  const [ingredientes, setIngredientes] = useState<IngForm[]>([{ itemId: '', quantidade: '' }]);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Exclus├úo
  const [preparoParaExcluir, setPreparoParaExcluir] = useState<Preparo | null>(null);
  const [isDeleting, setIsDeleting] = useState(false);

  // Clonagem
  const [isCloneOpen, setIsCloneOpen] = useState(false);
  const [escolas, setEscolas] = useState<{ id: string, name: string }[]>([]);
  const [escolaOrigemId, setEscolaOrigemId] = useState('');
  const [isCloning, setIsCloning] = useState(false);

  const { toast } = useToast();

  const fetchPreparos = async () => {
    setLoading(true);
    try {
      const res = await api.get(`/escolas/${escolaId}/preparos`, getHeaders());
      setPreparos(res.data);
    } catch (e) {
      console.error('Erro ao buscar preparos:', e);
    } finally {
      setLoading(false);
    }
  };

  const fetchFichas = async () => {
    try { const d = await getFichas(); setFichas(d); } catch (e) { console.error(e); }
  };

  const fetchCatalogo = async () => {
    try { const r = await api.get('/items', getHeaders()); setCatalogoItems(r.data); } catch (e) { console.error(e); }
  };

  const fetchEscolas = async () => {
    try {
      const r = await api.get('/escolas', getHeaders());
      // Filtrar a escola atual para n├úo aparecer na lista de origem
      setEscolas(r.data.filter((e: any) => e.id !== escolaId));
    } catch (e) { console.error(e); }
  };

  useEffect(() => {
    if (open) {
      setSearchTerm('');
      setFiltroTipo('TODOS');
      fetchPreparos();
      fetchFichas();
      fetchCatalogo();
      fetchEscolas();
    }
  }, [open, escolaId]);

  // Filtro client-side instant├óneo
  const filteredPreparos = useMemo(() => {
    let list = preparos;
    if (searchTerm.trim()) {
      const term = searchTerm.toLowerCase();
      list = list.filter(p => p.fichaTecnica.name.toLowerCase().includes(term));
    }
    if (filtroTipo !== 'TODOS') {
      list = list.filter(p => p.fichaTecnica.type?.toUpperCase() === filtroTipo);
    }
    return list;
  }, [preparos, searchTerm, filtroTipo]);

  // Tipos ├║nicos para filtro (derivados dos dados)
  const tiposUnicos = useMemo(() => {
    const s = new Set(preparos.map(p => p.fichaTecnica.type?.toUpperCase()).filter(Boolean));
    return Array.from(s) as string[];
  }, [preparos]);

  // Contagens por tipo para as tabs
  const contagensPorTipo = useMemo(() => {
    const counts: Record<string, number> = { TODOS: preparos.length };
    preparos.forEach(p => {
      const t = p.fichaTecnica.type?.toUpperCase();
      if (t) counts[t] = (counts[t] || 0) + 1;
    });
    return counts;
  }, [preparos]);

  // Fichas n├úo vinculadas ainda
  const fichasDisponiveis = useMemo(() => {
    const vinculadas = new Set(preparos.map(p => p.fichaTecnicaId));
    return fichas.filter(f => !vinculadas.has(f.id));
  }, [fichas, preparos]);

  // --- Form handlers ---
  const handleOpenAdd = () => {
    setEditingPreparo(null);
    setSelectedFichaId('');
    setIngredientes([{ itemId: '', quantidade: '' }]);
    setIsFormOpen(true);
  };

  const handleOpenEdit = (p: Preparo) => {
    setEditingPreparo(p);
    setSelectedFichaId(p.fichaTecnicaId);
    setIngredientes(p.ingredientes.map(i => ({ itemId: i.itemId, quantidade: i.quantidade })));
    setIsFormOpen(true);
  };

  const handleIngChange = (idx: number, field: keyof IngForm, val: string | number) => {
    setIngredientes(prev => prev.map((ing, i) => {
      if (i !== idx) return ing;
      if (field === 'quantidade') return { ...ing, quantidade: val === '' ? '' : Number(val) };
      if (field === 'itemId') return { ...ing, itemId: String(val) };
      return ing;
    }));
  };

  const handleSubmitForm = async () => {
    const fichaId = editingPreparo ? editingPreparo.fichaTecnicaId : selectedFichaId;
    if (!fichaId) {
      toast({ variant: "destructive", title: "Aten├º├úo", description: "Selecione uma ficha t├®cnica." });
      return;
    }
    const validos = ingredientes.filter(i => i.itemId && i.quantidade !== '' && Number(i.quantidade) > 0);
    if (validos.length === 0) {
      toast({ variant: "destructive", title: "Aten├º├úo", description: "Adicione pelo menos um ingrediente." });
      return;
    }
    setIsSubmitting(true);
    try {
      await api.post(`/escolas/${escolaId}/preparos`, {
        fichaTecnicaId: fichaId,
        ingredientes: validos.map(i => ({ itemId: i.itemId, quantidade: Number(i.quantidade) })),
      }, getHeaders());
      toast({ className: "bg-emerald-50 text-emerald-900 border-emerald-200", title: "Sucesso", description: "Preparo salvo." });
      setIsFormOpen(false);
      fetchPreparos();
    } catch (e: any) {
      console.error(e);
      toast({ variant: "destructive", title: "Erro", description: e.response?.data?.error || "Erro ao salvar preparo." });
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleConfirmDelete = async () => {
    if (!preparoParaExcluir) return;
    setIsDeleting(true);
    try {
      await api.delete(`/escolas/${escolaId}/preparos/${preparoParaExcluir.fichaTecnicaId}`, getHeaders());
      toast({ className: "bg-emerald-50 text-emerald-900 border-emerald-200", title: "Sucesso", description: "Preparo desvinculado." });
      fetchPreparos();
    } catch (e: any) {
      console.error(e);
      toast({ variant: "destructive", title: "Erro", description: e.response?.data?.error || "Erro ao desvincular." });
    } finally {
      setIsDeleting(false);
      setPreparoParaExcluir(null);
    }
  };

  const handleClone = async () => {
    if (!escolaOrigemId) {
      toast({ variant: "destructive", title: "Aten├º├úo", description: "Selecione a escola de origem." });
      return;
    }
    setIsCloning(true);
    try {
      await api.post(`/escolas/${escolaId}/clonar-preparos`, { escolaOrigemId }, getHeaders());
      toast({ className: "bg-emerald-50 text-emerald-900 border-emerald-200", title: "Sucesso", description: "Preparos clonados com sucesso!" });
      setIsCloneOpen(false);
      setEscolaOrigemId('');
      fetchPreparos();
    } catch (e: any) {
      console.error(e);
      toast({ variant: "destructive", title: "Erro na Importa├º├úo", description: e.response?.data?.error || "Erro ao clonar preparos." });
    } finally {
      setIsCloning(false);
    }
  };

  return (
    <>
      {/* ÔòÉÔòÉÔòÉ PAINEL FULL-SCREEN (90% da tela) ÔòÉÔòÉÔòÉ */}
      <Dialog open={open} onOpenChange={(o) => !o && onClose()}>
        <DialogContent
          className="w-[95vw] max-w-[1200px] h-[90vh] flex flex-col bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800 opacity-100 p-0 gap-0 overflow-hidden"
          onPointerDownOutside={(e) => e.preventDefault()}
          onEscapeKeyDown={(e) => e.preventDefault()}
        >

          {/* ÔöÇÔöÇ Cabe├ºalho fixo ÔöÇÔöÇ */}
          <div className="px-6 pt-6 pb-4 border-b border-slate-200 dark:border-slate-700 bg-gradient-to-r from-amber-50 via-orange-50 to-white dark:from-slate-800 dark:via-slate-800 dark:to-slate-900 flex-shrink-0">
            <DialogHeader className="mb-0">
              <DialogTitle className="text-xl font-bold text-slate-900 dark:text-slate-100 flex items-center gap-3">
                <div className="h-10 w-10 rounded-lg bg-blue-100 dark:bg-blue-900/30 flex items-center justify-center">
                  <ChefHat className="h-5 w-5 text-blue-600" />
                </div>
                <div>
                  <span className="block text-lg leading-tight">{escolaNome}</span>
                  <span className="block text-xs font-normal text-slate-500 dark:text-slate-400 mt-0.5">Gest├úo de Preparos e Ingredientes</span>
                </div>
              </DialogTitle>
              <DialogDescription className="sr-only">
                Configura├º├úo de receitas e ingredientes da escola {escolaNome}.
              </DialogDescription>
            </DialogHeader>

            {/* ÔöÇÔöÇ Busca + Filtros + Bot├úo ÔöÇÔöÇ */}
            <div className="flex flex-col sm:flex-row gap-3 items-start sm:items-center mt-4">
              <div className="relative flex-1 min-w-0">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                <Input
                  id="preparos-search"
                  placeholder="Buscar receita pelo nome..."
                  value={searchTerm}
                  onChange={e => setSearchTerm(e.target.value)}
                  className="pl-9 h-9 bg-white dark:bg-slate-950 border-slate-200 dark:border-slate-700"
                />
              </div>

              <Tabs value={filtroTipo} onValueChange={setFiltroTipo} className="flex-shrink-0">
                <TabsList className="bg-slate-100 dark:bg-slate-800 h-9">
                  <TabsTrigger value="TODOS" className="text-xs px-3 data-[state=active]:bg-blue-600 data-[state=active]:text-white">
                    Todos ({contagensPorTipo['TODOS'] || 0})
                  </TabsTrigger>
                  {tiposUnicos.map(t => (
                    <TabsTrigger key={t} value={t} className="text-xs px-3 data-[state=active]:bg-blue-600 data-[state=active]:text-white">
                      {t} ({contagensPorTipo[t] || 0})
                    </TabsTrigger>
                  ))}
                </TabsList>
              </Tabs>

              <div className="flex items-center gap-2 flex-shrink-0">
                <Button
                  size="sm"
                  variant="outline"
                  onClick={() => setIsCloneOpen(true)}
                  className="h-9 border-slate-200 text-slate-600 font-bold gap-1.5"
                >
                  <Copy className="h-3.5 w-3.5" /> Importar de outra Unidade
                </Button>
                <Button size="sm" onClick={handleOpenAdd} className="bg-blue-600 hover:bg-blue-700 text-white h-9 shadow-sm">
                  <Plus className="mr-1.5 h-3.5 w-3.5" /> Adicionar Novo Preparo
                </Button>
              </div>
            </div>
          </div>

          {/* ÔöÇÔöÇ Corpo scroll├ível ÔöÇÔöÇ */}
          <div className="flex-1 overflow-y-auto px-6 py-4">
            {loading ? (
              <div className="py-16 text-center">
                <div className="inline-flex items-center gap-2 text-slate-400">
                  <div className="h-4 w-4 border-2 border-amber-400 border-t-transparent rounded-full animate-spin" />
                  Carregando preparos...
                </div>
              </div>
            ) : filteredPreparos.length === 0 ? (
              <div className="py-16 text-center border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-xl">
                <UtensilsCrossed className="h-10 w-10 text-slate-300 dark:text-slate-600 mx-auto mb-3" />
                <p className="text-sm text-slate-500 dark:text-slate-400 font-medium">
                  {preparos.length === 0
                    ? 'Nenhum preparo configurado para esta escola.'
                    : 'Nenhum resultado para o filtro aplicado.'}
                </p>
                {preparos.length === 0 && (
                  <Button size="sm" variant="outline" onClick={handleOpenAdd} className="mt-4 text-amber-700 border-amber-300 hover:bg-amber-50">
                    <Plus className="mr-1 h-3 w-3" /> Configurar primeiro preparo
                  </Button>
                )}
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {filteredPreparos.map(p => {
                  const typeStyle = getTypeBadgeStyle(p.fichaTecnica.type);
                  return (
                    <Card
                      key={p.id}
                      className="shadow-sm border border-slate-200 dark:border-slate-700 hover:shadow-md transition-shadow duration-200 group"
                    >
                      <CardContent className="p-5">
                        {/* Header do Card */}
                        <div className="flex justify-between items-start mb-3">
                          <div className="flex items-start gap-3 min-w-0 flex-1">
                            <div className="h-9 w-9 rounded-lg bg-amber-50 dark:bg-amber-900/20 flex items-center justify-center flex-shrink-0 mt-0.5">
                              <UtensilsCrossed className="h-4 w-4 text-amber-600" />
                            </div>
                            <div className="min-w-0 flex-1">
                              <h4 className="font-semibold text-slate-800 dark:text-slate-200 text-sm leading-tight truncate">
                                {p.fichaTecnica.name}
                              </h4>
                              <div className="mt-1.5">
                                <Badge className={`${typeStyle.bg} ${typeStyle.text} ${typeStyle.border} border text-[10px] font-semibold px-2 py-0 hover:opacity-90`}>
                                  {p.fichaTecnica.type?.toUpperCase()}
                                </Badge>
                              </div>
                            </div>
                          </div>

                          {/* A├º├Áes */}
                          <div className="flex gap-1 ml-2 flex-shrink-0 opacity-70 group-hover:opacity-100 transition-opacity">
                            <Button
                              variant="outline"
                              size="sm"
                              className="h-8 px-2.5 text-xs text-blue-600 hover:text-blue-700 hover:bg-blue-50 border-blue-200 dark:border-blue-800"
                              onClick={() => handleOpenEdit(p)}
                              title="Editar ingredientes"
                            >
                              <Pencil className="h-3 w-3 mr-1" /> Editar
                            </Button>
                            <Button
                              variant="outline"
                              size="sm"
                              className="h-8 px-2.5 text-xs text-red-500 hover:text-red-700 hover:bg-red-50 border-red-200 dark:border-red-800"
                              onClick={() => setPreparoParaExcluir(p)}
                              title="Desvincular preparo"
                            >
                              <LinkIcon className="h-3 w-3 mr-1" /> Desvincular
                            </Button>
                          </div>
                        </div>

                        {/* Ingredientes */}
                        <div className="border-t border-slate-100 dark:border-slate-700 pt-3 mt-1">
                          <div className="flex items-center gap-1.5 mb-2">
                            <Package className="h-3 w-3 text-slate-400" />
                            <span className="text-[10px] text-slate-400 uppercase font-semibold tracking-wider">
                              Ingredientes ({p.ingredientes.length})
                            </span>
                          </div>
                          {p.ingredientes.length === 0 ? (
                            <p className="text-xs text-slate-400 italic">Nenhum ingrediente configurado.</p>
                          ) : (
                            <div className="flex flex-wrap gap-1.5">
                              {p.ingredientes.map(ing => (
                                <span
                                  key={ing.id}
                                  className="inline-flex items-center gap-1 text-[11px] bg-slate-50 dark:bg-slate-800 text-slate-600 dark:text-slate-300 rounded-md px-2 py-1 border border-slate-150 dark:border-slate-700"
                                >
                                  <span className="font-medium text-slate-700 dark:text-slate-200">{ing.item.name}</span>
                                  <span className="text-slate-400">┬À</span>
                                  <span className="text-amber-600 dark:text-amber-400 font-semibold">{ing.quantidade}</span>
                                  <span className="text-slate-400">{ing.item.baseUnit}</span>
                                </span>
                              ))}
                            </div>
                          )}
                        </div>
                      </CardContent>
                    </Card>
                  );
                })}
              </div>
            )}
          </div>

          {/* ÔöÇÔöÇ Rodap├® com contagem ÔöÇÔöÇ */}
          <div className="px-6 py-3 border-t border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800/50 flex-shrink-0">
            <div className="flex justify-between items-center">
              <span className="text-xs text-slate-500 dark:text-slate-400">
                {filteredPreparos.length} de {preparos.length} preparo{preparos.length !== 1 ? 's' : ''} exibido{filteredPreparos.length !== 1 ? 's' : ''}
              </span>
              <Button variant="outline" size="sm" onClick={onClose} className="h-8 text-xs text-slate-600 border-slate-300">
                Fechar
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>

      {/* ÔòÉÔòÉÔòÉ FORMUL├üRIO ADD/EDIT INGREDIENTES ÔòÉÔòÉÔòÉ */}
      <Dialog open={isFormOpen} onOpenChange={o => !o && setIsFormOpen(false)}>
        <DialogContent
          className="sm:max-w-[560px] max-h-[85vh] overflow-y-auto bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800 opacity-100"
          onPointerDownOutside={(e) => e.preventDefault()}
          onEscapeKeyDown={(e) => e.preventDefault()}
        >
          <DialogHeader>
            <DialogTitle className="text-slate-900 dark:text-slate-100 flex items-center gap-2">
              {editingPreparo ? (
                <><Pencil className="h-4 w-4 text-blue-600" /> Editar Preparo</>
              ) : (
                <><Plus className="h-4 w-4 text-amber-600" /> Novo Preparo</>
              )}
            </DialogTitle>
            <DialogDescription className="text-slate-500 dark:text-slate-400">
              {editingPreparo ? `Editando ingredientes de "${editingPreparo.fichaTecnica.name}"` : 'Selecione a receita e configure os ingredientes.'}
            </DialogDescription>
          </DialogHeader>

          <div className="flex flex-col gap-4 py-3">
            {!editingPreparo && (
              <div className="flex flex-col gap-2">
                <Label className="text-slate-900 dark:text-slate-200 font-semibold">Ficha T├®cnica</Label>
                <Select value={selectedFichaId} onValueChange={setSelectedFichaId}>
                  <SelectTrigger className="bg-white dark:bg-slate-950 text-slate-900 dark:text-slate-100"><SelectValue placeholder="Selecione a receita" /></SelectTrigger>
                  <SelectContent className="bg-white dark:bg-slate-950 border-slate-200 dark:border-slate-800">
                    {fichasDisponiveis.map(f => (
                      <SelectItem key={f.id} value={f.id} className="text-slate-900 dark:text-slate-100 focus:bg-slate-100 dark:focus:bg-slate-800">{f.name} ({f.type})</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                {fichasDisponiveis.length === 0 && <p className="text-xs text-amber-600">Todas as fichas j├í est├úo vinculadas a esta escola.</p>}
              </div>
            )}

            <div className="border-t border-slate-200 dark:border-slate-700 pt-3">
              <div className="flex justify-between items-center mb-3">
                <Label className="text-slate-900 dark:text-slate-200 font-semibold">Ingredientes</Label>
