          <Cpu className="h-40 w-40 text-blue-600" />
        </div>

        <div className="z-10">
          <h1 className="text-3xl font-bold text-slate-900 flex items-center gap-3">
            <Cpu className="h-8 w-8 text-blue-600" />
            Motor de Processamento
